  // Purchase Packaging State
  const [cwPurchaseForm, setCwPurchaseForm] = useState<{ purchase_date: string; supplier_ids: string[] }>({ purchase_date: mskTodayYmd(), supplier_ids: [] });
  const [cwPurchaseRows, setCwPurchaseRows] = useState<Array<{ id: string; quantity: string; size: string; price: string; delivery: string; newPrice?: boolean }>>([{ id: getSafeId(), quantity: '', size: '', price: '', delivery: '', newPrice: false }]);
  const [cwPurchaseOtherRows, setCwPurchaseOtherRows] = useState<Array<{ id: string; item_name: string; price: string }>>([{ id: getSafeId(), item_name: '', price: '' }]);
  const [cwPurchaseHistory, setCwPurchaseHistory] = useState<any[]>([]);
  const [cwPurchaseHistorySupplierFilter, setCwPurchaseHistorySupplierFilter] = useState('all');
  const [cwPurchaseEdit, setCwPurchaseEdit] = useState<any | null>(null);
  const [boxAdjustValue, setBoxAdjustValue] = useState('');
  const adjustBoxStock = async () => {
    const target = parseInt(boxAdjustValue);
    if (isNaN(target)) { showToast('Введите фактический остаток коробок', 'error'); return; }
    const delta = target - boxStock.remaining;
    if (delta === 0) { showToast('Остаток уже равен этому значению', 'info'); return; }
    const { error } = await supabase.from('packaging_purchase_log').insert([{ kind: 'packaging', size: 'Корректировка остатка коробок', quantity: delta, price: 0, delivery: 0, created_at: new Date().toISOString() }]);
    if (error) { showToast('Ошибка корректировки: ' + (error.message || 'неизвестно'), 'error'); return; }
    setBoxAdjustValue('');
    await fetchCwPurchaseHistory();
    await loadBoxStock();
    showToast(`Остаток скорректирован на ${delta > 0 ? '+' : ''}${delta} коробок`, 'success');
  };
  const saveCwPurchaseEdit = async () => {
    if (!cwPurchaseEdit) return;
    const e = cwPurchaseEdit;
    const patch: any = e.kind === 'other'
      ? { supplier_id: e.supplier_id || null, item_name: String(e.item_name || '').trim(), price: parseFloat(e.price) || 0 }
      : { supplier_id: e.supplier_id || null, size: String(e.size || '').trim(), quantity: parseInt(e.quantity) || 0, price: parseFloat(e.price) || 0, delivery: parseFloat(e.delivery) || 0 };
    if (String(e.created_at_date || '')) patch.created_at = new Date(`${e.created_at_date}T12:00:00`).toISOString();
    const { error } = await supabase.from('packaging_purchase_log').update(patch).eq('id', e.id);
    if (error) { showToast('Ошибка сохранения: ' + (error.message || 'неизвестно'), 'error'); return; }
    setCwPurchaseEdit(null);
    await fetchCwPurchaseHistory();
    await loadBoxStock();
    showToast('Запись обновлена', 'success');
  };
  // Packaging-type templates (dropdown in Закуп → Тип упаковки), each with a price.
  const [packagingTypeTemplates, setPackagingTypeTemplates] = useState<Array<{ name: string; price: number }>>([]);
  const [showPackagingTemplateModal, setShowPackagingTemplateModal] = useState(false);
  const [packagingNewTemplate, setPackagingNewTemplate] = useState('');
  const [packagingNewTemplatePrice, setPackagingNewTemplatePrice] = useState('');

  const loadPackagingTypeTemplates = async () => {
    try {
      const { data } = await supabase.from('app_settings').select('value').eq('key', 'packaging_type_templates_v1').maybeSingle();
      const raw = (data as any)?.value;
      const arr = Array.isArray(raw) ? raw : (typeof raw === 'string' ? JSON.parse(raw || '[]') : []);
      const norm = (arr || [])
        .map((x: any) => typeof x === 'string' ? { name: String(x || '').trim(), price: 0 } : { name: String(x?.name || '').trim(), price: Number(x?.price || 0) })
        .filter((x: any) => x.name);
      const seen = new Set<string>();
      setPackagingTypeTemplates(norm.filter((x: any) => (seen.has(x.name) ? false : (seen.add(x.name), true))));
    } catch { /* ignore */ }
  };
  const savePackagingTypeTemplates = async (items: Array<{ name: string; price: number }>) => {
    const seen = new Set<string>();
    const clean = items
      .map((x) => ({ name: String(x.name || '').trim(), price: Number(x.price || 0) }))
      .filter((x) => x.name && (seen.has(x.name) ? false : (seen.add(x.name), true)));
    setPackagingTypeTemplates(clean);
    await supabase.from('app_settings').upsert([{ key: 'packaging_type_templates_v1', value: JSON.stringify(clean) }], { onConflict: 'key' });
  };

  const fetchCwPurchaseHistory = async () => {
    const { data, error } = await supabase
      .from('packaging_purchase_log')
      .select('id, created_at, quantity, size, price, delivery, supplier_id, kind, item_name')
      .is('deleted_at', null)
      .order('created_at', { ascending: false });

    if (error) {
      if (/relation .* does not exist|schema cache/i.test(String(error.message || ''))) {
        showToast('Нет таблицы packaging_purchase_log в БД. Нужно создать миграцию.', 'error');
      } else {
        console.error('fetchCwPurchaseHistory error:', error);
      }
      return;
    }

    setCwPurchaseHistory(Array.isArray(data) ? data : []);
  };

  // Edit State
  const [editingRateId, setEditingRateId] = useState<string | null>(null);
  const [inlineRateEdit, setInlineRateEdit] = useState<{ id: string; name: string; price: string } | null>(null);
  const [editingPackagingId, setEditingPackagingId] = useState<string | null>(null);

  // Save/create a work rate (shared by the top form and inline card editing).
  const submitWorkRate = async (overrideName?: string, overridePrice?: string, rateId?: string | null) => {
    if (!hasAssemblyButtonAccess('cw_rates_save')) return;
    const name = String(overrideName ?? cwRateForm.name).trim();
    const price = String(overridePrice ?? cwRateForm.price);
    const targetId = rateId !== undefined ? rateId : editingRateId;
    if (!name || !price) return;
    if (targetId) {
      const before = cwWorkRates.find((r: any) => String(r.id) === String(targetId));
      const newPrice = parseFloat(price);
      await supabase.from('work_rates').update({ name, price: newPrice }).eq('id', targetId);
      const nextRateHistory = { ...(cwWorkRateHistory || {}) } as Record<string, Array<{ changed_at: string; price: number; old_price?: number | null; new_price?: number | null; name?: string }>>;
      const rateKey = String(targetId);
      const currentHistory = Array.isArray(nextRateHistory[rateKey]) ? nextRateHistory[rateKey] : [];
      const oldPrice = Number(before?.price ?? 0);
      nextRateHistory[rateKey] = [...currentHistory, { changed_at: new Date().toISOString(), price: newPrice, old_price: oldPrice, new_price: newPrice, name }];
      setCwWorkRateHistory(nextRateHistory);
      await supabase.from('app_settings').upsert([{ key: 'cw_work_rate_history_v1', value: JSON.stringify(nextRateHistory) }], { onConflict: 'key' });
      await logAssemblyChange('work_rates', 'update', before || null, { ...(before || {}), name, price: newPrice });
      setEditingRateId(null);
    } else {
      let createdRate: any = null;
      const primaryInsert = await supabase.from('work_rates').insert([{ name, price: parseFloat(price), use_shared_price: true }]).select('*').maybeSingle();
      if (primaryInsert.error) {
        const fallbackInsert = await supabase.from('work_rates').insert([{ name, price: parseFloat(price) }]).select('*').maybeSingle();
        createdRate = fallbackInsert.data || null;
      } else { createdRate = primaryInsert.data || null; }
      await logAssemblyChange('work_rates', 'create', null, createdRate || { name, price: parseFloat(price) });
    }
    setCwRateForm({ name: '', price: '' });
    const { data } = await supabase.from('work_rates').select('*').is('deleted_at', null);
    setCwWorkRates(data || []);
    await loadCwWorkRateEmployeePrices(data || []);
    if (cwSelectedEmployee?.id) {
      const startOfMonth = `${cwSelectedPeriod.getFullYear()}-${String(cwSelectedPeriod.getMonth() + 1).padStart(2, '0')}-01`;
      const endOfMonth = `${cwSelectedPeriod.getFullYear()}-${String(cwSelectedPeriod.getMonth() + 1).padStart(2, '0')}-${String(new Date(cwSelectedPeriod.getFullYear(), cwSelectedPeriod.getMonth() + 1, 0).getDate()).padStart(2, '0')}`;
      const { data: refreshedLogs } = await supabase.from('work_logs').select('*').eq('employee_id', cwSelectedEmployee.id).gte('date', startOfMonth).lte('date', endOfMonth).is('deleted_at', null);
      setCwWorkLogs(refreshedLogs || []);
    }
  };

  // Report Dates State
