  const fetchSupplyItemsWithHonestSign = async (boxIds: string[], selectClause = 'box_id') => {
    if (!boxIds.length) return [] as any[];

    const pageSize = 1000;
    const chunkSize = 200;
    const allItems: any[] = [];

    for (let i = 0; i < boxIds.length; i += chunkSize) {
      const boxIdsChunk = boxIds.slice(i, i + chunkSize);
      let from = 0;

      while (true) {
        const { data, error } = await supabase
          .from('supply_items')
          .select(selectClause)
          .in('box_id', boxIdsChunk)
          .is('deleted_at', null)
          .not('honest_sign_code', 'is', null)
          .neq('honest_sign_code', '')
          .order('id', { ascending: true })
          .range(from, from + pageSize - 1);

        if (error) throw error;

        const chunk = data || [];
        allItems.push(...chunk);
        if (chunk.length < pageSize) break;
        from += pageSize;
      }
    }

    return allItems;
  };

  const fetchHonestSignCodes = async (supplierId: string) => {
    setLoadingHonestSign(true);

    try {
      const { data: supplies, error: suppliesError } = await supabase
        .from('supplies')
        .select('*')
        .eq('supplier_id', supplierId)
        .is('deleted_at', null)
        .order('created_at', { ascending: false });

      if (suppliesError) throw suppliesError;

      if (!supplies || supplies.length === 0) {
        setHonestSignCodes([]);
        return;
      }

      const supplyIds = supplies.map((s) => s.id);
      const { data: allBoxes, error: boxesError } = await supabase
        .from('boxes')
        .select('id, supply_id')
        .in('supply_id', supplyIds)
        .is('deleted_at', null);

      if (boxesError) throw boxesError;

      const boxesBySupply = (allBoxes || []).reduce((acc: any, box: any) => {
        if (!acc[box.supply_id]) acc[box.supply_id] = [];
        acc[box.supply_id].push(box.id);
        return acc;
      }, {});

      const allBoxIds = (allBoxes || []).map((b: any) => b.id);
      // Одна выборка строк ЧЗ для всех целей (счётчик + пол). Дедуп по id —
      // страховка от возможных дублей строк на границах страниц пагинации.
      const itemsRaw = await fetchSupplyItemsWithHonestSign(allBoxIds, 'id, box_id, honest_sign_code');
      const seenItemIds = new Set<string>();
      const itemsWithCodes = itemsRaw.filter((item: any) => {
        const id = String(item?.id || '');
        if (!id || seenItemIds.has(id)) return false;
        seenItemIds.add(id);
        return true;
      });

      const boxCounts: Record<string, number> = {};
      itemsWithCodes.forEach((item: any) => {
        const boxId = String(item?.box_id || '');
        if (!boxId) return;
        boxCounts[boxId] = (boxCounts[boxId] || 0) + 1;
      });

      const suppliesWithCounts = supplies.map((s) => {
        const sBoxIds = boxesBySupply[s.id] || [];
        const count = sBoxIds.reduce((acc: number, boxId: string) => acc + (boxCounts[boxId] || 0), 0);
        return { ...s, code_count: count, gender_label: '-' };
      });

      try {
        const uniqueCodes = Array.from(new Set(itemsWithCodes.map((item: any) => String(item?.honest_sign_code || '').trim()).filter(Boolean)));
        const codeGenderMap = new Map<string, string>();
        const hsChunkSize = 1000;

        for (let i = 0; i < uniqueCodes.length; i += hsChunkSize) {
          const chunk = uniqueCodes.slice(i, i + hsChunkSize);
          const { data: genderRows, error: genderError } = await supabase
            .from('unified_honest_sign_codes')
            .select('code, gender')
            .eq('supplier_id', supplierId)
            .in('code', chunk);

          if (genderError) throw genderError;
          (genderRows || []).forEach((row: any) => {
            const code = String(row?.code || '').trim();
            if (!code) return;
            codeGenderMap.set(code, normalizeHSGender(row?.gender));
          });
        }

        const boxGenderSets: Record<string, Set<string>> = {};
        itemsWithCodes.forEach((item: any) => {
          const boxId = String(item?.box_id || '');
          const code = String(item?.honest_sign_code || '').trim();
          const gender = normalizeHSGender(codeGenderMap.get(code) || '');
          if (!boxId || !gender) return;
          if (!boxGenderSets[boxId]) boxGenderSets[boxId] = new Set<string>();
          boxGenderSets[boxId].add(gender);
        });

        suppliesWithCounts.forEach((s: any) => {
          const sBoxIds = boxesBySupply[s.id] || [];
          const genderSet = new Set<string>();
          sBoxIds.forEach((boxId: string) => {
            (boxGenderSets[boxId] || new Set<string>()).forEach((gender) => genderSet.add(gender));
          });
          s.gender_label = genderSet.size === 1
            ? getHSGenderLabel(Array.from(genderSet)[0])
            : genderSet.size > 1
              ? 'Смешанный'
              : '-';
        });
      } catch (genderLoadError) {
        console.warn('Optional Honest Sign gender enrichment skipped:', genderLoadError);
      }

      setHonestSignCodes(suppliesWithCounts.filter((s) => s.code_count > 0));
    } catch (error) {
      console.error('Error loading Honest Sign codes:', error);
      setHonestSignCodes([]);
      showToast('Ошибка загрузки базы ЧЗ', 'error');
    } finally {
      setLoadingHonestSign(false);
    }
  };

  const handleReturnCodes = async () => {
    if (!returnCodesInput.trim()) return;

    const codes = Array.from(new Set(returnCodesInput.split(/[\n\s,]+/).map(c => c.trim()).filter(Boolean)));
    if (codes.length === 0) return;

    try {
      const { data: foundRows, error: findError } = await supabase
        .from('unified_honest_sign_codes')
        .select('id,code,category,supplier_id')
        .in('code', codes)
        .eq('supplier_id', honestSignSupplierId);

      if (findError) throw findError;

      const rows = foundRows || [];
      if (rows.length === 0) {
        showToast('Коды не найдены у выбранного поставщика', 'error');
        return;
      }

      const ids = rows.map((r: any) => r.id).filter(Boolean);
      const nowIso = new Date().toISOString();

      const { error: updateError } = await supabase
        .from('unified_honest_sign_codes')
        .update({
          file_name: `Возврат ${new Date().toLocaleDateString('ru-RU')}`,
          status: 'new',
          created_at: nowIso
        })
        .in('id', ids);

      if (updateError) throw updateError;

      const foundCodes = new Set(rows.map((r: any) => String(r.code)));
      const missed = codes.filter(c => !foundCodes.has(c));

      if (missed.length > 0) {
        showToast(`Возвращено ${rows.length} кодов. Не найдено: ${missed.length}`, 'warning');
      } else {
        showToast(`Возвращено ${rows.length} кодов (категории восстановлены автоматически)`, 'success');
      }

      setReturnCodesInput('');
      setShowReturnCodesModal(false);
      fetchHonestSignUploadHistory();
      fetchHonestSignPrintedHistory();
      fetchHonestSignCategoryStats();
    } catch (e: any) {
      console.error('Return codes error:', e);
      showToast(`Ошибка возврата кодов: ${e?.message || 'неизвестно'}`, 'error');
    }
  };

  const importHonestSignCodes = async (codes: string[], fileName: string) => {
    if (codes.length === 0) {
      showToast('Файл пуст или не содержит кодов', 'error');
      return;
    }

    if (!honestSignSupplierId) {
      showToast('Выберите поставщика', 'error');
      return;
    }

    if (!honestSignBaseCategory) {
      showToast('Выберите категорию', 'error');
      return;
    }

    const normalizedGender = normalizeHSGender(honestSignBaseGender);
    if (!normalizedGender) {
      showToast('Выберите пол: мужской или женский', 'error');
      return;
    }

    try {
      setLoadingHonestSign(true);

      const uniqueCodes = Array.from(new Set(codes.map(c => String(c).trim()).filter(Boolean)));
      const checkChunkSize = 80;
      const duplicates: string[] = [];

      for (let i = 0; i < uniqueCodes.length; i += checkChunkSize) {
        const chunk = uniqueCodes.slice(i, i + checkChunkSize);
        const { data: existing, error: checkError } = await supabase
          .from('unified_honest_sign_codes')
          .select('code')
          .in('code', chunk);

        if (checkError) throw checkError;
        if (existing) duplicates.push(...existing.map(c => c.code));
      }

      const duplicateSet = new Set(duplicates);
      const codesToInsert = uniqueCodes.filter(code => !duplicateSet.has(code));

      if (codesToInsert.length === 0) {
        showToast(`Все коды (${uniqueCodes.length}) уже существуют в базе`, 'warning');
        return;
      }

      const dataToInsert = codesToInsert.map(code => ({
        supplier_id: honestSignSupplierId,
        category: normalizeHSCategory(honestSignBaseCategory),
        gender: normalizedGender,
        code,
        file_name: fileName,
        status: 'new'
      }));

      const chunkSize = 250;
      for (let i = 0; i < dataToInsert.length; i += chunkSize) {
        const chunk = dataToInsert.slice(i, i + chunkSize);
        const { error } = await supabase.from('unified_honest_sign_codes').insert(chunk);
        if (error) throw error;
      }

      if (duplicates.length > 0) {
        showToast(`Загружено ${codesToInsert.length} кодов. Пропущено дубликатов: ${duplicates.length}`, 'warning');
      } else {
        showToast(`Успешно загружено ${codesToInsert.length} кодов`, 'success');
      }

      setHonestSignBaseCategory('');
      setHonestSignBaseGender('');
      fetchHonestSignUploadHistory();
      fetchHonestSignCategoryStats();
    } catch (error: any) {
      console.error('Error uploading codes:', error);
      showToast(`Ошибка при загрузке кодов: ${error.message || 'Неизвестная ошибка'}`, 'error');
    } finally {
      setLoadingHonestSign(false);
    }
  };

  const parseCodesFromFile = async (file: File): Promise<string[]> => {
    const fileSizeError = ensureExcelFileSize(file);
    if (fileSizeError) {
      throw new Error(fileSizeError);
    }

    const lowerName = String(file.name || '').toLowerCase();

    if (lowerName.endsWith('.xlsx') || lowerName.endsWith('.xls')) {
      const data = await file.arrayBuffer();
      const jsonData = await readFirstSheetAsJson<any[]>(data, { header: 1 });
      const rowLimitError = ensureExcelRowLimit(jsonData.length);
      if (rowLimitError) {
        throw new Error(rowLimitError);
      }
      return jsonData.map(row => row[0] ? String(row[0]).trim() : '').filter(c => c.length > 0);
    }

    const text = await file.text();
    const lines = text.split(/\r?\n/).map(line => line.trim()).filter(line => line.length > 0);
    const rowLimitError = ensureExcelRowLimit(lines.length);
    if (rowLimitError) {
      throw new Error(rowLimitError);
    }
    return lines;
  };

  const handleHonestSignBaseUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const codes = await parseCodesFromFile(file);
      await importHonestSignCodes(codes, file.name);
    } catch (error: any) {
      console.error('Honest Sign file upload error:', error);
      showToast(`Ошибка чтения файла: ${error?.message || 'неизвестно'}`, 'error');
    } finally {
      if (e.target) e.target.value = '';
    }
  };

  const handleHonestSignBaseImportFromTelegram = async () => {
    if (!honestSignSupplierId) {
      showToast('Выберите поставщика', 'error');
      return;
    }

    if (!honestSignBaseCategory) {
      showToast('Сначала выберите категорию', 'error');
      return;
    }

    const supplier = suppliers.find(s => s.id === honestSignSupplierId);
    if (!supplier?.telegram_chat_id) {
      showToast('У поставщика не заполнен Telegram Chat ID', 'error');
      return;
    }

    const token = telegramBotToken.trim();
    if (!token) {
      showToast('Не настроен Telegram bot token', 'error');
      return;
    }

    try {
      setLoadingHonestSign(true);
      const updatesJson = await telegramService.getUpdates(token, 100);
      if (!updatesJson?.ok) throw new Error(updatesJson?.description || 'Telegram getUpdates error');

      const chatId = String(supplier.telegram_chat_id);
      const updates = (updatesJson.result || [])
        .map((u: any) => u?.message)
        .filter((m: any) => m && String(m?.chat?.id) === chatId && m?.document)
        .sort((a: any, b: any) => (b?.date || 0) - (a?.date || 0));

      const msg = updates[0];
      if (!msg?.document?.file_id) {
        showToast('В Telegram не найден файл-документ для выбранного поставщика', 'warning');
        return;
      }

      const fileId = msg.document.file_id;
      const originalName = msg.document.file_name || `telegram_${Date.now()}.txt`;

      const fileJson = await telegramService.getFile(token, fileId);
      if (!fileJson?.ok || !fileJson?.result?.file_path) throw new Error(fileJson?.description || 'Telegram getFile error');

      const dlUrl = telegramService.getFileDownloadUrl(token, fileJson.result.file_path);
      const dlRes = await fetch(dlUrl);
      if (!dlRes.ok) throw new Error(`Ошибка скачивания файла: ${dlRes.status}`);

      const blob = await dlRes.blob();
      const file = new File([blob], originalName, { type: blob.type || 'application/octet-stream' });
      const codes = await parseCodesFromFile(file);

      await importHonestSignCodes(codes, `tg_${originalName}`);
    } catch (e: any) {
      console.error('Telegram import error:', e);
      showToast(`Ошибка импорта из Telegram: ${e?.message || 'неизвестно'}`, 'error');
    } finally {
      setLoadingHonestSign(false);
    }
  };

  const handleDownloadHonestSign = async () => {
    if (!honestSignCodes.length) return;

    try {
      const supplyIds = honestSignCodes.map((s) => s.id);
      const { data: boxes, error: boxesError } = await supabase
        .from('boxes')
        .select('id, supply_id, supply:supplies(name)')
        .in('supply_id', supplyIds)
        .is('deleted_at', null);

      if (boxesError) throw boxesError;

      if (!boxes || boxes.length === 0) {
        showToast('Коробки не найдены', 'error');
        return;
      }

      const boxIds = boxes.map((b) => b.id);
      const boxSupplyMap = new Map(boxes.map((b) => [b.id, (b.supply as any)?.name]));
      const items = await fetchSupplyItemsWithHonestSign(boxIds, 'id, box_id, honest_sign_code, product:products(barcode)');

      if (!items || items.length === 0) {
        showToast('Коды не найдены', 'error');
        return;
      }

      const rows = items.map((item) => ({
        'Баркод товара': (item.product as any)?.barcode || '',
        'Честный знак': item.honest_sign_code,
        'Номер поставки': boxSupplyMap.get(item.box_id) || 'Unknown'
      }));

      await downloadWorkbook(`HonestSign_${new Date().toLocaleDateString()}.xlsx`, [
        {
          name: 'Честный Знак',
          rows,
          headers: ['Баркод товара', 'Честный знак', 'Номер поставки'],
          widths: [20, 50, 30],
        },
      ]);
    } catch (error: any) {
      console.error('Export error:', error);
      showToast('Ошибка экспорта: ' + error.message, 'error');
    }
  };

  const handleDownloadHonestSignSupply = async (supply: any) => {
    try {
      const { data: boxes, error: boxesError } = await supabase
        .from('boxes')
        .select('id')
        .eq('supply_id', supply.id)
        .is('deleted_at', null);

      if (boxesError) throw boxesError;
      const boxIds = (boxes || []).map((b: any) => b.id);
      if (!boxIds.length) { showToast('Коробки не найдены', 'error'); return; }

      const itemsRaw = await fetchSupplyItemsWithHonestSign(boxIds, 'id, honest_sign_code, product:products(barcode)');
      const seen = new Set<string>();
      const items = itemsRaw.filter((it: any) => {
        const id = String(it?.id || '');
        if (!id || seen.has(id)) return false;
        seen.add(id); return true;
      });
      if (!items.length) { showToast('Коды не найдены', 'error'); return; }

      const rows = items.map((item: any) => ({
        'Баркод товара': (item.product as any)?.barcode || '',
        'Честный знак': item.honest_sign_code,
        'Номер поставки': supply.name || '',
      }));

      const safe = String(supply.name || 'supply').replace(/[\\/:*?"<>|]/g, '_');
      await downloadWorkbook(`ЧЗ_${safe}.xlsx`, [
        { name: 'Честный Знак', rows, headers: ['Баркод товара', 'Честный знак', 'Номер поставки'], widths: [20, 50, 30] },
      ]);
    } catch (error: any) {
      console.error('Export error:', error);
      showToast('Ошибка экспорта: ' + error.message, 'error');
    }
  };

  const handleDeleteHonestSign = (supplyId: string) => {
    openConfirmModal(
      'Удаление кодов',
      'Вы уверены, что хотите удалить коды честного знака для этой поставки?',
      async () => {
        try {
          const { data: boxes } = await supabase.from('boxes').select('id').eq('supply_id', supplyId);
          if (boxes && boxes.length > 0) {
            const boxIds = boxes.map(b => b.id);
            const { error } = await supabase.from('supply_items').update({ honest_sign_code: null }).in('box_id', boxIds).not('honest_sign_code', 'is', null);
            if (error) throw error;
          }
          showToast('Коды удалены', 'success');
          if (honestSignSupplierId) fetchHonestSignCodes(honestSignSupplierId);
        } catch (error) {
          console.error('Error deleting codes:', error);
          showToast('Ошибка при удалении кодов', 'error');
        }
        setConfirmModal(prev => ({ ...prev, isOpen: false }));
      }
    );
  };

  useEffect(() => {
    if (honestSignSupplierId) fetchHonestSignCodes(honestSignSupplierId);
    else setHonestSignCodes([]);
  }, [honestSignSupplierId]);

  useEffect(() => {
    fetchSuppliers();

    const channel = supabase
      .channel('db_changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'suppliers' }, () => fetchSuppliers())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => {
        fetchProducts(selectedSupplierId || '');
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedSupplierId]);

  const showToast = (message: string, type: NotificationType = 'success') => {
    const newNotification = { id: getSafeId(), message, type, time: new Date() };
    setNotification(newNotification);
    setNotificationHistory(prev => [newNotification, ...prev]);

    if (notificationTimeoutRef.current) {
      window.clearTimeout(notificationTimeoutRef.current);
    }

    notificationTimeoutRef.current = window.setTimeout(() => {
      setNotification(prev => (prev?.id === newNotification.id ? null : prev));
      notificationTimeoutRef.current = null;
    }, 5000);
  };

  useEffect(() => {
    return () => {
      if (notificationTimeoutRef.current) {
        window.clearTimeout(notificationTimeoutRef.current);
      }
    };
  }, []);

  const describeWarehouseOfflineError = (error: any, url: string) => {
    const baseMessage = String(error?.message || error || 'Сервер недоступен');

    try {
      const serverUrl = new URL(String(url || '').trim());
      const pageUrl = new URL(window.location.href);
      const serverHost = serverUrl.hostname;
      const pageHost = pageUrl.hostname;
      const loopbackHosts = ['localhost', '127.0.0.1', '[::1]'];

      if (loopbackHosts.includes(serverHost) && !loopbackHosts.includes(pageHost)) {
        return `${baseMessage}. На планшете localhost указывает на сам планшет. Откройте SkladPro через http://IP-компьютера:8787 или укажите адрес сервера http://192.168.1.111:8787.`;
      }

      if (pageUrl.protocol === 'https:' && serverUrl.protocol === 'http:' && !loopbackHosts.includes(serverHost)) {
        return `${baseMessage}. Браузер может блокировать запрос с HTTPS-сайта к локальному HTTP-серверу. На планшете откройте SkladPro напрямую через ${serverUrl.origin}.`;
      }
    } catch {
      // Keep the original network error if URL parsing fails.
    }

    return baseMessage;
  };

  const saveWarehouseOfflineSettings = (enabled: boolean, url = warehouseOfflineUrl) => {
    const cleanUrl = String(url || '').trim().replace(/\/+$/, '') || getDefaultWarehouseOfflineUrl();
    setWarehouseOfflineEnabled(enabled);
    setWarehouseOfflineUrl(cleanUrl);
    setWarehouseOfflineEnabledState(enabled);
    setWarehouseOfflineUrlState(cleanUrl);
  };

  const checkWarehouseOfflineServer = async (showSuccess = true) => {
    try {
      const status = await warehouseOfflineClient.health();
      setWarehouseOfflineStatus(status);
      if (showSuccess) showToast('Локальный складской сервер доступен', 'success');
      return status;
    } catch (e: any) {
      const status = { ok: false, error: describeWarehouseOfflineError(e, warehouseOfflineUrl) } as WarehouseOfflineStatus;
      setWarehouseOfflineStatus(status);
      showToast('Локальный сервер недоступен: ' + status.error, 'error');
      return status;
    }
  };

  const getWarehouseOfflineSnapshotOrEmpty = async (): Promise<WarehouseOfflineSnapshot> => {
    const snapshot = await warehouseOfflineClient.getSnapshot();
    const fallback: WarehouseOfflineSnapshot = {
      createdAt: new Date().toISOString(),
      suppliers: [],
      wbProducts: [],
      modelNumbers: {},
      labelLayout: null,
      fboSupplies: [],
      fboBoxes: [],
      honestSignSeen: [],
    };
    return {
      ...fallback,
      ...(snapshot || {}),
      suppliers: Array.isArray(snapshot?.suppliers) ? snapshot.suppliers : [],
      wbProducts: Array.isArray(snapshot?.wbProducts) ? snapshot.wbProducts : [],
      modelNumbers: snapshot?.modelNumbers && typeof snapshot.modelNumbers === 'object' ? snapshot.modelNumbers : {},
      fboSupplies: Array.isArray(snapshot?.fboSupplies) ? snapshot.fboSupplies : [],
      fboBoxes: Array.isArray(snapshot?.fboBoxes) ? snapshot.fboBoxes : [],
      honestSignSeen: Array.isArray(snapshot?.honestSignSeen) ? snapshot.honestSignSeen : [],
    };
  };

  const saveWarehouseOfflineSnapshotState = async (snapshot: WarehouseOfflineSnapshot) => {
    const normalized = { ...snapshot, createdAt: snapshot.createdAt || new Date().toISOString() };
    await warehouseOfflineClient.saveSnapshot(normalized, warehouseOfflineStatus?.version);
    wbSkuIndexRef.current = {};
    supplierProductsIndexRef.current = {};
    setWarehouseOfflineSnapshot(normalized);
    await checkWarehouseOfflineServer(false);
    return normalized;
  };

  const normalizeWarehouseOfflineSupply = (row: any): Supply => ({
    id: String(row?.id || ''),
    supplier_id: String(row?.supplier_id || row?.supplierId || ''),
    name: String(row?.name || ''),
    status: String(row?.status || 'active'),
    created_at: String(row?.created_at || row?.createdAt || new Date().toISOString()),
    updated_at: row?.updated_at || row?.updatedAt,
    total_items: getOfflineSupplyItemsCount(row),
  });

  const normalizeWarehouseOfflineBox = (row: any): SupplyBox => ({
    id: String(row?.id || ''),
    supply_id: String(row?.supply_id || row?.supplyId || ''),
    name: String(row?.name || ''),
    created_at: String(row?.created_at || row?.createdAt || new Date().toISOString()),
    total_items: getOfflineBoxItemsCount(row),
  });

  const loadWarehouseOfflineSnapshot = async (applyToList = true) => {
    const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
    setWarehouseOfflineSnapshot(snapshot);
    if (applyToList) {
      const supplies = (snapshot.fboSupplies || [])
        .map(normalizeWarehouseOfflineSupply)
        .filter((s) => s.id && (!selectedSupplierId || String(s.supplier_id) === String(selectedSupplierId)))
        .sort((a, b) => new Date(String(b.created_at || '')).getTime() - new Date(String(a.created_at || '')).getTime());
      setSuppliesList(supplies);
    }
    return snapshot;
  };

  const getWarehouseOfflineSuppliers = () => {
    const list = Array.isArray(warehouseOfflineSnapshot?.suppliers) ? warehouseOfflineSnapshot.suppliers : [];
    return (list.length ? list : suppliers) as Supplier[];
  };

  const getWarehouseOfflineSupplyBoxes = (snapshot: WarehouseOfflineSnapshot, supplyId: string) => {
    return (snapshot.fboBoxes || [])
      .map(normalizeWarehouseOfflineBox)
      .filter((box) => box.id && String(box.supply_id) === String(supplyId))
      .sort((a, b) => new Date(String(b.created_at || '')).getTime() - new Date(String(a.created_at || '')).getTime());
  };

  const buildWarehouseOfflineSnapshot = async () => {
    const [productsRes, modelRes, layoutRes, suppliesRes, boxesRes, hsRes] = await Promise.all([
      supabase.from('wb_products_cache').select('supplier_id, nm_id, product_json').limit(20000),
      supabase.from('app_settings').select('value').eq('key', 'wb_model_numbers_v1').maybeSingle(),
      supabase.from('app_settings').select('value').eq('key', 'wb_label_layout_v1').maybeSingle(),
      supabase.from('supplies').select('*, boxes(supply_items(count))').is('deleted_at', null).order('created_at', { ascending: false }),
      supabase.from('boxes').select('*, supply_items(count)').is('deleted_at', null).order('created_at', { ascending: false }),
      supabase.from('unified_honest_sign_codes').select('code').or('file_name.eq.Отсканировано,status.eq.scanned').limit(50000),
    ]);

    const errors = [productsRes.error, modelRes.error, layoutRes.error, suppliesRes.error, boxesRes.error, hsRes.error].filter(Boolean);
    if (errors.length) throw errors[0];

    const modelRaw: any = modelRes.data?.value || {};
    const modelParsed = typeof modelRaw === 'string' ? JSON.parse(modelRaw || '{}') : modelRaw;
    const models = (modelParsed?.models && typeof modelParsed.models === 'object' ? modelParsed.models : modelParsed) || {};
    const layoutRaw: any = layoutRes.data?.value || null;
    const labelLayout = typeof layoutRaw === 'string' ? JSON.parse(layoutRaw || 'null') : layoutRaw;
    const fboSupplies = (suppliesRes.data || []).map((supply: any) => ({
      ...supply,
      total_items: getOfflineSupplyItemsCount(supply),
    }));
    const fboBoxes = (boxesRes.data || []).map((box: any) => ({
      ...box,
      total_items: getOfflineBoxItemsCount(box),
    }));

    return {
      createdAt: new Date().toISOString(),
      suppliers,
      wbProducts: (productsRes.data || []).map((row: any) => ({ ...(row?.product_json || {}), supplierId: row?.supplier_id, nmID: row?.product_json?.nmID || Number(row?.nm_id || 0) })),
      modelNumbers: models,
      labelLayout,
      fboSupplies,
      fboBoxes,
      honestSignSeen: (hsRes.data || []).map((row: any) => String(row?.code || '').trim()).filter(Boolean),
    };
  };

  const refreshWarehouseOfflineBase = async () => {
    setWarehouseOfflineBusy(true);
    try {
      saveWarehouseOfflineSettings(true);
      await checkWarehouseOfflineServer(false);
      const snapshot = await buildWarehouseOfflineSnapshot();
      const previousSnapshot = await warehouseOfflineClient.getSnapshot().catch(() => null);
      const previousProductsCount = Array.isArray(previousSnapshot?.wbProducts) ? previousSnapshot.wbProducts.length : 0;
      const nextProductsCount = Array.isArray(snapshot.wbProducts) ? snapshot.wbProducts.length : 0;

      if (nextProductsCount === 0) {
        showToast(
          previousProductsCount > 0
            ? 'WB товары не загрузились, старая offline-база сохранена. Проверьте интернет и обновите Товары WB.'
            : 'WB товары не загрузились. Сначала обновите Товары WB при наличии интернета.',
          'error'
        );
        return null;
      }

      await warehouseOfflineClient.saveSnapshot(snapshot, warehouseOfflineStatus?.version);
      wbSkuIndexRef.current = {};
      supplierProductsIndexRef.current = {};
      setWarehouseOfflineSnapshot(snapshot);
      setSuppliesList((snapshot.fboSupplies || []).map(normalizeWarehouseOfflineSupply).sort((a, b) => new Date(String(b.created_at || '')).getTime() - new Date(String(a.created_at || '')).getTime()));
      const status = await checkWarehouseOfflineServer(false);
      showToast('Offline-база обновлена: товаров ' + snapshot.wbProducts.length + ', поставок ' + snapshot.fboSupplies.length, 'success');
      return status;
    } catch (e: any) {
      showToast('Ошибка обновления offline-базы: ' + (e?.message || 'неизвестно'), 'error');
      return null;
    } finally {
      setWarehouseOfflineBusy(false);
    }
  };

  const syncWarehouseOfflineScans = async (silent = false) => {
    if (warehouseOfflineSyncingRef.current) return;
    warehouseOfflineSyncingRef.current = true;
    setWarehouseOfflineBusy(true);
    try {
      const scans = await warehouseOfflineClient.getFboScans();
      const pending = (scans.pending || []) as any[];
      if (!pending.length) {
        if (!silent) showToast('Нет локальных FBO-сканов для синхронизации', 'info');
        await checkWarehouseOfflineServer(false);
        return;
      }

      // Each pending scan carries its local id -> used as offline_scan_id so a
      // retry after a partial failure is idempotent (unique index in DB).
      const rows = pending
        .map((row) => ({
          offlineId: String(row.id || ''),
          box_id: row.box_id || row.boxId,
          product_id: row.product_id || row.productId,
          honest_sign_code: row.honest_sign_code || row.code,
        }))
        .filter((row) => row.offlineId && row.box_id && row.product_id && row.honest_sign_code);

      if (!rows.length) throw new Error('В локальной очереди нет корректных строк для отправки');

      const toPayload = (r: typeof rows[number]) => ({
        box_id: r.box_id,
        product_id: r.product_id,
        honest_sign_code: r.honest_sign_code,
        offline_scan_id: r.offlineId,
      });

      const syncedIds: string[] = [];
      const syncedCodes: string[] = [];
      const conflicts: Array<{ id: string; error?: string }> = [];

      // Try the whole batch first (fast path). On any error fall back to
      // per-row upserts so one bad row cannot block the rest.
      const batch = await supabase
        .from('supply_items')
        .upsert(rows.map(toPayload), { onConflict: 'offline_scan_id', ignoreDuplicates: true });

      if (!batch.error) {
        rows.forEach((r) => { syncedIds.push(r.offlineId); syncedCodes.push(r.honest_sign_code); });
      } else {
        for (const r of rows) {
          const { error } = await supabase
            .from('supply_items')
            .upsert([toPayload(r)], { onConflict: 'offline_scan_id', ignoreDuplicates: true });
          if (error) {
            conflicts.push({ id: r.offlineId, error: error.message || 'Ошибка вставки' });
          } else {
            syncedIds.push(r.offlineId);
            syncedCodes.push(r.honest_sign_code);
          }
        }
      }

      if (syncedCodes.length) {
        await syncScannedCodesToUnifiedBase(syncedCodes, currentSupply?.supplier_id);
        await warehouseOfflineClient.markFboScansSynced(syncedIds);
      }
      if (conflicts.length) {
        await warehouseOfflineClient.moveFboScansToConflicts(conflicts).catch(() => undefined);
      }

      await checkWarehouseOfflineServer(false);
      if (currentBox?.id) await fetchBoxItems(currentBox.id);
      if (currentSupply?.id) await fetchSupplyStats(currentSupply.id);

      if (conflicts.length) {
        showToast(`Синхронизировано: ${syncedIds.length}, конфликтов: ${conflicts.length} (см. очередь)`, 'warning');
      } else if (syncedIds.length || !silent) {
        showToast('Синхронизировано FBO-сканов: ' + syncedIds.length, 'success');
      }
    } catch (e: any) {
      if (!silent) showToast('Ошибка синхронизации offline-сканов: ' + (e?.message || 'неизвестно'), 'error');
    } finally {
      warehouseOfflineSyncingRef.current = false;
      setWarehouseOfflineBusy(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'supplies' && warehouseOfflineEnabled) {
      checkWarehouseOfflineServer(false).catch(() => undefined);
      loadWarehouseOfflineSnapshot(true).catch(() => undefined);
    }
  }, [activeTab, warehouseOfflineEnabled]);

  // Periodic heartbeat + auto-sync of the offline queue while the supplies tab
  // is open. Keeps the online/offline badge fresh and flushes pending scans as
  // soon as the local server is reachable, without a manual button press.
  useEffect(() => {
    if (activeTab !== 'supplies' || !warehouseOfflineEnabled) return;
    let stopped = false;

    const tick = async () => {
      if (stopped) return;
      const status = await checkWarehouseOfflineServer(false).catch(() => null);
      if (stopped) return;
      if (status?.ok && Number(status?.pendingScans || 0) > 0 && !warehouseOfflineSyncingRef.current) {
        await syncWarehouseOfflineScans(true).catch(() => undefined);
      }
    };

    const onOnline = () => { tick().catch(() => undefined); };
    const intervalId = window.setInterval(() => { tick().catch(() => undefined); }, 20000);
    window.addEventListener('online', onOnline);

    return () => {
      stopped = true;
      window.clearInterval(intervalId);
      window.removeEventListener('online', onOnline);
    };
  }, [activeTab, warehouseOfflineEnabled]);

  useEffect(() => {
    const clearIssueTimer = () => {
      if (supabaseIssueHideTimerRef.current) {
        window.clearTimeout(supabaseIssueHideTimerRef.current);
        supabaseIssueHideTimerRef.current = null;
      }
    };

    const onIssue = () => {
      setSupabaseConnectionIssue('Проблема соединения с Supabase. Данные могут не загружаться.');
      clearIssueTimer();
      supabaseIssueHideTimerRef.current = window.setTimeout(() => {
        setSupabaseConnectionIssue((prev) => prev === 'Проблема соединения с Supabase. Данные могут не загружаться.' ? null : prev);
        supabaseIssueHideTimerRef.current = null;
      }, 6000);
    };

    const onOk = () => {
      clearIssueTimer();
      setSupabaseConnectionIssue(null);
    };

    window.addEventListener('supabase:connection-issue', onIssue as EventListener);
    window.addEventListener('supabase:connection-ok', onOk as EventListener);
    window.addEventListener('online', onOk as EventListener);
    window.addEventListener('offline', onIssue as EventListener);

    return () => {
      clearIssueTimer();
      window.removeEventListener('supabase:connection-issue', onIssue as EventListener);
      window.removeEventListener('supabase:connection-ok', onOk as EventListener);
      window.removeEventListener('online', onOk as EventListener);
      window.removeEventListener('offline', onIssue as EventListener);
    };
  }, []);

  const {
    warehouseAssignments,
    setWarehouseAssignments,
    warehouseAssignmentsDirty,
    setWarehouseAssignmentsDirty,
  } = useWarehousePersistence(activeTab, showToast);



  // Supplies State
  const [supplyStep, setSupplyStep] = useState<'LIST' | 'SUPPLY' | 'BOX' | 'HONEST_SIGN'>('LIST');
  // Активный сборщик (для учёта выработки по сканам). Сбрасывается ежедневно.
  const [activeScannerEmployee, setActiveScannerEmployeeState] = useState<{ id: string; name: string } | null>(() => {
    try {
      const raw = localStorage.getItem('scladpro_active_scanner');
      if (!raw) return null;
      const o = JSON.parse(raw);
      if (o && o.id && o.date === mskTodayYmd()) return { id: o.id, name: o.name };
    } catch {}
    return null;
  });
  const setActiveScannerEmployee = useCallback((emp: { id: string; name: string } | null) => {
    setActiveScannerEmployeeState(emp);
    try {
      if (emp) localStorage.setItem('scladpro_active_scanner', JSON.stringify({ ...emp, date: mskTodayYmd() }));
      else localStorage.removeItem('scladpro_active_scanner');
    } catch {}
  }, []);
  // Кто пишется в скан: активный бейдж > залогиненный сотрудник.
  const resolveScannerId = useCallback(() => activeScannerEmployee?.id || (currentEmployee as any)?.id || null, [activeScannerEmployee, currentEmployee]);
  const [currentSupply, setCurrentSupply] = useState<Supply | null>(null);
  const [currentBox, setCurrentBox] = useState<SupplyBox | null>(null);
  const [scannedItem, setScannedItem] = useState<Product | null>(null);
