  const [fboPalletProductPicker, setFboPalletProductPicker] = useState<{ open: boolean; palletId: string }>({ open: false, palletId: '' });
  const [fboPalletProducts, setFboPalletProducts] = useState<FboPalletProductOption[]>([]);
