  const openFboPalletItemQtyEdit = (item: FboPalletItem) => {
    setFboPalletItemQtyEdit({ id: item.id, title: item.title || '', qty: String(Math.max(1, Number(item.qty || 1))) });
  };

  const handleSaveFboPalletItemQtyEdit = async () => {
    const edit = fboPalletItemQtyEdit;
    if (!edit) return;
    const qty = Math.floor(Number(edit.qty));
    if (!Number.isFinite(qty) || qty < 1) {
      showToast('Введите целое число больше 0', 'error');
      return;
    }
    try {
      const snapshot = await loadFboPalletSnapshot();
      await saveFboPalletSnapshot({
        ...snapshot,
        items: snapshot.items.map((it) => String(it.id) === String(edit.id) ? { ...it, qty } : it),
      });
      setFboPalletItemQtyEdit(null);
      await fetchFboPalletData(fboPalletSupplierId);
      logAction('ФБО: изменение количества', `Товар «${edit.title || edit.id}» → ${qty} шт`, currentEmployee?.id);
      showToast('Количество обновлено', 'success');
    } catch (e: any) {
      showToast('Ошибка изменения количества: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const handleAddFboPallet = async () => {
    const supplierId = String(fboPalletSupplierId || '').trim();
    if (!supplierId) {
      showToast('Выберите поставщика для паллет', 'error');
      return;
    }
    if (!fboPalletSelectedWarehouseId) {
      showToast('Сначала выберите или создайте склад поставки', 'error');
      return;
    }
    if (!fboPalletSelectedSupplyId) {
      showToast('Сначала выберите или создайте поставку', 'error');
      return;
    }

    try {
      const { session, snapshot } = await getFboPalletActiveSession(supplierId);
      const currentPallets = snapshot.pallets.filter((p) => String(p.session_id) === String(session.id) && String(p.supply_id || '') === String(fboPalletSelectedSupplyId) && !p.deleted_at);
      const used = new Set(currentPallets.map((p) => Number(p.pallet_number)).filter((n) => Number.isFinite(n) && n > 0));
      let nextNumber = 1;
      while (used.has(nextNumber)) nextNumber += 1;

      const pallet: FboPallet = {
        id: createFboPalletId('fbo-pallet'),
        session_id: session.id,
        supplier_id: supplierId,
        warehouse_id: fboPalletSelectedWarehouseId,
        supply_id: fboPalletSelectedSupplyId,
        pallet_number: nextNumber,
        created_at: new Date().toISOString(),
        deleted_at: null,
      };
      await saveFboPalletSnapshot({ ...snapshot, pallets: [...snapshot.pallets, pallet] });
      await fetchFboPalletData(supplierId);
      logAction('ФБО: создание паллеты', `Паллета №${nextNumber} · поставщик ${suppliers.find((s:any)=>String(s.id)===supplierId)?.name || supplierId}`, currentEmployee?.id);
      showToast('Паллета №' + nextNumber + ' добавлена', 'success');
    } catch (e: any) {
      showToast('Ошибка добавления паллеты: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const openFboPalletProductPicker = (palletId: string) => {
    setFboPalletSelectedProducts({});
    setFboPalletProductPicker({ open: true, palletId });
  };

  const closeFboPalletProductPicker = () => {
    setFboPalletSelectedProducts({});
    setFboPalletProductPicker({ open: false, palletId: '' });
  };

  const setFboPalletSelectedProductQty = (productKey: string, qty: number) => {
    const cleanQty = Math.max(1, Math.min(999, Math.floor(Number(qty) || 1)));
    setFboPalletSelectedProducts((prev) => ({ ...prev, [productKey]: cleanQty }));
  };

  const toggleFboPalletSelectedProduct = (productKey: string, checked: boolean) => {
    setFboPalletSelectedProducts((prev) => {
      const next = { ...prev };
      if (checked) next[productKey] = next[productKey] || 1;
      else delete next[productKey];
      return next;
    });
  };

  const handleAddSelectedProductsToFboPallet = async () => {
    const palletId = String(fboPalletProductPicker.palletId || '').trim();
    const supplierId = String(fboPalletSupplierId || '').trim();
    if (!palletId || !supplierId) return;

    const selectedProducts = fboPalletProducts.filter((product) => fboPalletSelectedProducts[product.key]);
    if (selectedProducts.length === 0) {
      showToast('Выберите товары для паллеты', 'error');
      return;
    }

    try {
      const barcodes = Array.from(new Set(selectedProducts.map((product) => String(product.barcode || '').trim()).filter(Boolean)));
      const productIdsByBarcode = new Map<string, string>();
      if (barcodes.length > 0) {
        const { data } = await supabase
          .from('products')
          .select('id, barcode')
          .eq('supplier_id', supplierId)
          .in('barcode', barcodes)
          .is('deleted_at', null)
          .limit(1000);
        (data || []).forEach((row: any) => {
          const barcode = String(row?.barcode || '').trim();
          if (barcode && row?.id) productIdsByBarcode.set(barcode, String(row.id));
        });
      }

      const snapshot = await loadFboPalletSnapshot();
      const now = new Date().toISOString();
      const items = selectedProducts.map((product) => {
        const barcode = String(product.barcode || '').trim();
        const qty = Math.max(1, Math.floor(Number(fboPalletSelectedProducts[product.key]) || 1));
        return {
          id: createFboPalletId('fbo-pallet-item'),
          pallet_id: palletId,
          supplier_id: supplierId,
          product_id: productIdsByBarcode.get(barcode) || null,
          nm_id: product.nm_id || null,
          barcode: product.barcode || null,
          vendor_code: product.vendor_code || null,
          title: product.title,
          size: product.size || null,
          color: product.color || null,
          photo_url: product.photo_url || null,
          qty,
          product_json: product.product_json || null,
          created_at: now,
          deleted_at: null,
        } as FboPalletItem;
      });
      await saveFboPalletSnapshot({ ...snapshot, items: [...items, ...snapshot.items] });

      await fetchFboPalletData(supplierId);
      const totalQty = items.reduce((a, it: any) => a + Number(it.qty || 0), 0);
      logAction('ФБО: товары в паллету', `Добавлено позиций: ${items.length} (${totalQty} шт): ${items.slice(0,5).map((it:any)=>it.title).join(', ')}${items.length>5?'…':''}`, currentEmployee?.id);
      closeFboPalletProductPicker();
      showToast('Товары добавлены в паллету: ' + items.length, 'success');
    } catch (e: any) {
      showToast('Ошибка добавления товаров в паллету: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const handleDeleteFboPalletItem = async (itemId: string) => {
    try {
      const snapshot = await loadFboPalletSnapshot();
      const deletedAt = new Date().toISOString();
      const delItem = snapshot.items.find((it) => String(it.id) === String(itemId));
      await saveFboPalletSnapshot({
        ...snapshot,
        items: snapshot.items.map((item) => String(item.id) === String(itemId) ? { ...item, deleted_at: deletedAt } : item),
      });
      await fetchFboPalletData(fboPalletSupplierId);
      logAction('ФБО: удаление товара из паллеты', `Товар «${delItem?.title || itemId}»${delItem?.qty ? ` (${delItem.qty} шт)` : ''}`, currentEmployee?.id);
    } catch (e: any) {
      showToast('Ошибка удаления товара из паллеты: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const handleDeleteFboPallet = async (palletId: string) => {
    try {
      const snapshot = await loadFboPalletSnapshot();
      const deletedAt = new Date().toISOString();
      const delPallet = snapshot.pallets.find((p) => String(p.id) === String(palletId));
      await saveFboPalletSnapshot({
        ...snapshot,
        pallets: snapshot.pallets.map((pallet) => String(pallet.id) === String(palletId) ? { ...pallet, deleted_at: deletedAt } : pallet),
        items: snapshot.items.map((item) => String(item.pallet_id) === String(palletId) ? { ...item, deleted_at: deletedAt } : item),
      });
      await fetchFboPalletData(fboPalletSupplierId);
      logAction('ФБО: удаление паллеты', `Паллета №${delPallet?.pallet_number ?? palletId}`, currentEmployee?.id);
    } catch (e: any) {
      showToast('Ошибка удаления паллеты: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const handleDeleteFboPalletWarehouse = async (warehouseId: string) => {
    const id = String(warehouseId || '').trim();
    if (!id) return;
    try {
      const snapshot = await loadFboPalletSnapshot();
      const warehouse = snapshot.warehouses.find((w) => String(w.id) === id);
      const supplyIds = new Set(
        snapshot.supplies.filter((s) => String(s.warehouse_id) === id).map((s) => String(s.id))
      );
      const palletIds = new Set(
        snapshot.pallets
          .filter((p) => String(p.warehouse_id || '') === id || supplyIds.has(String(p.supply_id || '')))
          .map((p) => String(p.id))
      );
      const activePallets = snapshot.pallets.filter((p) => palletIds.has(String(p.id)) && !p.deleted_at).length;
      const confirmed = await confirmDialog(
        activePallets > 0
          ? `Удалить склад «${warehouse?.name || id}»? Вместе с ним будут полностью удалены поставки, паллеты (${activePallets}) и их товары.`
          : `Удалить склад «${warehouse?.name || id}»?`
      );
      if (!confirmed) return;

      // Физическое удаление: убираем склад, его поставки, паллеты и товары из снапшота
      await saveFboPalletSnapshot({
        ...snapshot,
        warehouses: snapshot.warehouses.filter((w) => String(w.id) !== id),
        supplies: snapshot.supplies.filter((s) => !supplyIds.has(String(s.id))),
        pallets: snapshot.pallets.filter((p) => !palletIds.has(String(p.id))),
        items: snapshot.items.filter((item) => !palletIds.has(String(item.pallet_id))),
      });
      if (String(fboPalletSelectedWarehouseId) === id) {
        setFboPalletSelectedWarehouseId('');
        setFboPalletSelectedSupplyId('');
      }
      await fetchFboPalletData(fboPalletSupplierId);
      logAction('ФБО: удаление склада поставки', `Склад «${warehouse?.name || id}»${activePallets > 0 ? ` (паллет: ${activePallets})` : ''}`, currentEmployee?.id);
      showToast('Склад удалён', 'success');
    } catch (e: any) {
      showToast('Ошибка удаления склада: ' + (e?.message || 'неизвестно'), 'error');
    }
  };

  const getFboPalletScannedCount = async (product: Product) => {
    if (!currentSupply) return 0;
    const productId = String(product?.id || '').trim();
    const barcode = String(product?.barcode || '').trim();
    const nmId = String(product?.nm_id || product?.wb_sku || '').trim();

    try {
      if (warehouseOfflineEnabled) {
        const scans = await warehouseOfflineClient.getFboScans().catch(() => ({ pending: [], synced: [] }));
        const rows = [...((scans.pending || []) as any[]), ...((scans.synced || []) as any[])];
        return rows.filter((row: any) => {
          if (String(row?.supply_id || row?.supplyId || '') !== String(currentSupply.id)) return false;
          if (productId && String(row?.product_id || row?.productId || '') === productId) return true;
          if (barcode && String(row?.product_barcode || row?.barcode || '') === barcode) return true;
          return false;
        }).length;
      }

      if (fboOfflineMode) {
        const session = offlineFboSessionRef.current && offlineFboSessionRef.current.supply_id === currentSupply.id ? offlineFboSessionRef.current : buildEmptyOfflineFboSession(currentSupply);
        return (session.items || []).filter((item: any) => {
          const itemProduct = item?.product || {};
          if (productId && String(item?.product_id || itemProduct?.id || '') === productId) return true;
          if (barcode && String(itemProduct?.barcode || '') === barcode) return true;
          if (nmId && String(itemProduct?.nm_id || itemProduct?.wb_sku || '') === nmId) return true;
          return false;
        }).length;
      }

      if (!productId || productId.startsWith('offline-product-')) return 0;
      const { data: boxes, error: boxesError } = await supabase
        .from('supply_boxes')
        .select('id')
        .eq('supply_id', currentSupply.id)
        .is('deleted_at', null);
      if (boxesError) throw boxesError;
      const boxIds = (boxes || []).map((box: any) => String(box.id)).filter(Boolean);
      if (boxIds.length === 0) return 0;

      const { count, error } = await supabase
        .from('supply_items')
        .select('id', { count: 'exact', head: true })
        .in('box_id', boxIds)
        .eq('product_id', productId)
        .is('deleted_at', null);
      if (error) throw error;

      const pendingCount = pendingScansRef.current.filter((scan) => String(scan.productId || '') === productId).length;
      return Number(count || 0) + pendingCount;
    } catch (e) {
      console.warn('getFboPalletScannedCount failed', e);
      return 0;
    }
  };

  const findFboPalletHint = async (product: Product): Promise<FboPalletHint | null> => {
    const supplierId = String(currentSupply?.supplier_id || product?.supplier_id || '').trim();
    if (!supplierId) return null;

    try {
      const productId = String(product?.id || '').trim();
      const barcode = String(product?.barcode || '').trim();
      const nmId = String(product?.nm_id || product?.wb_sku || '').trim();
      if ((!productId || productId.startsWith('offline-product-')) && !barcode && !nmId) return null;

      const snapshot = await loadFboPalletSnapshot();
      // Include deleted warehouses/supplies too: a pallet may still reference a
      // soft-deleted one, and we still want to show its name in the scan hint.
      const warehouseById = new Map(snapshot.warehouses.map((warehouse) => [String(warehouse.id), warehouse]));
      const supplyById = new Map((snapshot.supplies || []).map((supply) => [String(supply.id), supply]));
      const activeSessionIds = new Set(snapshot.sessions
        .filter((session) => String(session.supplier_id) === supplierId && session.status === 'active' && !session.deleted_at)
        .map((session) => String(session.id)));
      const activePallets = snapshot.pallets.filter((pallet) => activeSessionIds.has(String(pallet.session_id)) && !pallet.deleted_at);
      const activePalletById = new Map(activePallets.map((pallet) => [String(pallet.id), pallet]));
      const activePalletIds = new Set(activePallets.map((pallet) => String(pallet.id)));
      const matchingItems = snapshot.items
        .filter((item) => String(item.supplier_id) === supplierId && !item.deleted_at && activePalletIds.has(String(item.pallet_id)))
        .filter((item) => {
          if (productId && !productId.startsWith('offline-product-') && item.product_id && String(item.product_id) === productId) return true;
          if (barcode && item.barcode && String(item.barcode) === barcode) return true;
          if (nmId && item.nm_id && String(item.nm_id) === nmId) return true;
          return false;
        })
        .sort((a, b) => {
          const palletA = activePalletById.get(String(a.pallet_id));
          const palletB = activePalletById.get(String(b.pallet_id));
          const numberDiff = Number(palletA?.pallet_number || 0) - Number(palletB?.pallet_number || 0);
          if (numberDiff !== 0) return numberDiff;
          return String(a.created_at || '').localeCompare(String(b.created_at || ''));
        });
      if (matchingItems.length === 0) return null;

      // Prefer items on pallets that belong to a real (non-deleted) warehouse.
      // Orphaned legacy pallets without a warehouse_id must not win the hint when
      // a properly-assigned pallet holds the same product — otherwise the worker
      // sees "Склад: не указан" even though the product is on a named pallet.
      const palletHasWarehouse = (palletId?: string | null) => {
        const pal = activePalletById.get(String(palletId || ''));
        const wh = pal ? warehouseById.get(String(pal.warehouse_id || '')) : null;
        return !!(wh && !wh.deleted_at);
      };
      const warehouseBacked = matchingItems.filter((item) => palletHasWarehouse(item.pallet_id));
      const effectiveItems = warehouseBacked.length > 0 ? warehouseBacked : matchingItems;

      const scannedQty = await getFboPalletScannedCount(product);
      let cumulativeQty = 0;
      const data = effectiveItems.find((item) => {
        cumulativeQty += Math.max(1, Number(item.qty || 1));
        return scannedQty < cumulativeQty;
      });
      const pallet = activePalletById.get(String(data?.pallet_id || ''));
      if (!data || !pallet?.pallet_number) return null;
      const warehouse = warehouseById.get(String(pallet.warehouse_id || ''));
      const supply = supplyById.get(String(pallet.supply_id || ''));
      const targetQty = Math.max(1, Number(data.qty || 1));
      return {
        warehouse_name: warehouse?.name || '',
        supply_name: supply?.name || '',
        supply_date: supply?.date || '',
        pallet_number: Number(pallet.pallet_number),
        item_title: String(data.title || product.name || ''),
        item_size: data.size || product.size || '',
        item_color: data.color || product.color || '',
        target_qty: targetQty,
        scanned_qty: Math.max(0, scannedQty - (cumulativeQty - targetQty)),
      };
    } catch (e) {
      console.warn('findFboPalletHint failed', e);
      return null;
    }
  };

  const fetchBoxItems = async (boxId: string) => {
    if (!boxId) {
      setBoxItems([]);
      return;
    }
    if (fboOfflineMode && currentSupply) {
      const session = offlineFboSession && offlineFboSession.supply_id === currentSupply.id ? offlineFboSession : buildEmptyOfflineFboSession(currentSupply);
      setBoxItems((session.items || []).filter((item) => item.box_id === boxId).sort((a, b) => String(b.created_at).localeCompare(String(a.created_at))));
      return;
    }
    if (warehouseOfflineEnabled) {
      try {
        const scans = await warehouseOfflineClient.getFboScans();
        const rows = [...((scans.pending || []) as any[]), ...((scans.synced || []) as any[])]
          .filter((row) => String(row?.box_id || row?.boxId || '') === String(boxId))
          .sort((a, b) => String(b.createdAt || b.created_at || '').localeCompare(String(a.createdAt || a.created_at || '')));
        setBoxItems(rows.map((row: any) => ({
          id: String(row.id || `warehouse-offline-${row.honest_sign_code || row.code || Math.random()}`),
          box_id: String(row.box_id || row.boxId || boxId),
          product_id: String(row.product_id || row.productId || ''),
          honest_sign_code: String(row.honest_sign_code || row.code || ''),
          created_at: String(row.created_at || row.createdAt || new Date().toISOString()),
          product: {
            id: String(row.product_id || row.productId || ''),
            supplier_id: String(row.supplier_id || currentSupply?.supplier_id || ''),
            name: String(row.product_name || ''),
            wb_sku: String(row.product_barcode || ''),
            barcode: String(row.product_barcode || ''),
            size: String(row.product_size || ''),
            color: String(row.product_color || ''),
            model_number: String(row.product_model_number || ''),
            created_at: String(row.created_at || row.createdAt || ''),
          } as Product,
        })));
      } catch (e) {
        setBoxItems([]);
      }
      return;
    }
    const { data } = await supabase.from('supply_items').select('*, product:products(*)').eq('box_id', boxId).order('created_at', { ascending: false });
    setBoxItems(data || []);
  };

  useEffect(() => {
    if (currentBox) fetchBoxItems(currentBox.id);
  }, [currentBox, fboOfflineMode, offlineFboSession, warehouseOfflineEnabled]);

  const ensureWbSkuIndex = async (supplierId: string) => {
    if (wbSkuIndexRef.current[supplierId]) return wbSkuIndexRef.current[supplierId];

    const index = new Map<string, { card: any; size: any }>();
    const addSkuToIndex = (sku: unknown, card: any, size: any = null) => {
      const key = String(sku || '').trim();
      if (key && !index.has(key)) index.set(key, { card, size });
    };

    if (warehouseOfflineEnabled) {
      const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
      setWarehouseOfflineSnapshot(snapshot);
      for (const card of (snapshot.wbProducts || []) as any[]) {
        const cardSupplierId = String(card?.supplierId || card?.supplier_id || card?.supplierID || '');
        // Строго: товар должен явно принадлежать текущему поставщику.
        // Карточки без supplier_id НЕ индексируем — иначе чужой ШК попадает в чужую поставку.
        if (String(cardSupplierId) !== String(supplierId)) continue;
        addSkuToIndex(card?.barcode, card);
        const cardSkus = [
          ...(Array.isArray(card?.skus) ? card.skus : []),
          ...(Array.isArray(card?.barcodes) ? card.barcodes : []),
        ];
        cardSkus.forEach((sku) => addSkuToIndex(sku, card));
        const sizes = Array.isArray(card?.sizes) ? card.sizes : [];
        for (const size of sizes) {
          const skus = Array.isArray(size?.skus) ? size.skus : [];
          for (const sku of skus) addSkuToIndex(sku, card, size);
        }
      }
      wbSkuIndexRef.current[supplierId] = index;
      return index;
    }

    const pageSize = 200;
    let from = 0;

    while (true) {
      const { data: rows, error } = await supabase
        .from('wb_products_cache')
        .select('product_json')
        .eq('supplier_id', supplierId)
        .range(from, from + pageSize - 1);

      if (error) throw error;

      const chunk = rows || [];
      for (const row of chunk as any[]) {
        const card = row?.product_json;
        addSkuToIndex(card?.barcode, card);
        const cardSkus = [
          ...(Array.isArray(card?.skus) ? card.skus : []),
          ...(Array.isArray(card?.barcodes) ? card.barcodes : []),
        ];
        cardSkus.forEach((sku) => addSkuToIndex(sku, card));
        const sizes = Array.isArray(card?.sizes) ? card.sizes : [];
        for (const size of sizes) {
          const skus = Array.isArray(size?.skus) ? size.skus : [];
          for (const sku of skus) addSkuToIndex(sku, card, size);
        }
      }

      if (chunk.length < pageSize) break;
      from += pageSize;
    }

    wbSkuIndexRef.current[supplierId] = index;
    return index;
  };

  const ensureSupplierProductsIndex = async (supplierId: string) => {
    if (supplierProductsIndexRef.current[supplierId]) return supplierProductsIndexRef.current[supplierId];

    const index = new Map<string, Product>();

    if (warehouseOfflineEnabled || fboOfflineMode) {
      supplierProductsIndexRef.current[supplierId] = index;
      return index;
    }

    const pageSize = 200;
    let from = 0;

    while (true) {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .eq('supplier_id', supplierId)
        .is('deleted_at', null)
        .range(from, from + pageSize - 1);

      if (error) throw error;

      const chunk = (data || []) as Product[];
      for (const p of chunk) {
        if (p?.barcode) index.set(String(p.barcode), p);
      }

      if (chunk.length < pageSize) break;
      from += pageSize;
    }

    supplierProductsIndexRef.current[supplierId] = index;
    return index;
  };

  const ensureWbModelNumbers = async () => {
    if (wbModelNumbersRef.current.loaded) return wbModelNumbersRef.current.values;
    try {
      const { data } = await supabase.from('app_settings').select('value').eq('key', 'wb_model_numbers_v1').maybeSingle();
      const parsed = data?.value ? (typeof data.value === 'string' ? JSON.parse(data.value) : data.value) : {};
      const source = (parsed?.models && typeof parsed.models === 'object' ? parsed.models : parsed) as Record<string, string>;
      const values: Record<string, string> = {};
      Object.entries(source || {}).forEach(([key, value]) => {
        const cleanKey = String(key || '').trim();
        const cleanValue = String(value || '').trim();
        if (cleanKey && cleanValue) values[cleanKey] = cleanValue;
      });
      wbModelNumbersRef.current = { loaded: true, values };
      return values;
    } catch (e) {
      console.warn('Failed to load WB model numbers for FBO scan card', e);
      wbModelNumbersRef.current = { loaded: true, values: {} };
      return {};
    }
  };

  const preloadOfflineFboIndexes = useCallback(async (supplierId: string) => {
    if (!supplierId) return;
    if (wbSkuIndexRef.current[supplierId] && supplierProductsIndexRef.current[supplierId]) return;
    if (!offlineFboIndexesWarmupRef.current[supplierId]) {
      offlineFboIndexesWarmupRef.current[supplierId] = Promise.all([
        ensureWbSkuIndex(supplierId),
        ensureSupplierProductsIndex(supplierId),
      ]).then(() => undefined).finally(() => {
        delete offlineFboIndexesWarmupRef.current[supplierId];
      });
    }
    await offlineFboIndexesWarmupRef.current[supplierId];
  }, []);

  // Прогреваем индексы SKU/товаров заранее (при открытии поставки), чтобы первый
  // скан не ждал ~4с построения индекса из wb_products_cache.
  useEffect(() => {
    const sid = currentSupply?.supplier_id;
    if (!sid) return;
    preloadOfflineFboIndexes(sid);
    ensureWbModelNumbers();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentSupply?.supplier_id]);

  // Бейдж сборщика: WRK:<employeeId>. Возвращает true, если код распознан как бейдж.
  const tryHandleWorkerBadge = (raw: string): boolean => {
    const m = String(raw || '').trim().match(/^WRK[:;]\s*([0-9a-fA-F-]{6,})$/);
    if (!m) return false;
    const id = m[1];
    const emp = (employees || []).find((e: any) => String(e.id) === id);
    if (!emp) {
      playScanTone('error');
      showToast('Бейдж сборщика не распознан (сотрудник не найден)', 'error');
      return true;
    }
    setActiveScannerEmployee({ id: String(emp.id), name: emp.full_name || 'Сотрудник' });
    playScanTone('success');
    showToast(`Сканирует: ${emp.full_name || 'Сотрудник'}`, 'success');
    return true;
  };

  const handleItemScan = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentSupply) return;

    let input = (itemInputRef.current?.value || '').trim();
    if (!input) return;
    if (itemInputRef.current) itemInputRef.current.value = ''; // Clear immediately for speed

    if (/[\p{Script=Cyrillic}]/u.test(input)) {
       input = fixLayout(input);
       showToast('Раскладка исправлена', 'info');
    }

    if (tryHandleWorkerBadge(input)) return;

    if (input.trim() === 'ACTION:NEW_BOX' || input.trim() === 'NEW_BOX' || input.includes('NEW_BOX') || input.includes('ACTION;NEW_BOX')) {
      finishCurrentBoxAndReturn();
      return;
    }

    if (input.trim() === 'ACTION:GENERATE_BOX' || input.trim() === 'action:generate_box' || input.includes('GENERATE_BOX') || input.includes('generate_box') || input.includes('ACTION;GENERATE_BOX')) {
      await createNextBoxInCurrentSupply();
      return;
    }

    // Search scanned item in WB products cache (shared DB table), not in manual products section.
    let product = null;
    let matchedCard: any = null;
    let matchedSize: any = null;

    try {
      if (fboOfflineMode) {
        await preloadOfflineFboIndexes(currentSupply.supplier_id);
      }

      let skuIndex = await ensureWbSkuIndex(currentSupply.supplier_id);
      let hit = skuIndex.get(String(input).trim());

      // One forced re-index attempt only for online mode
      if (!hit && !fboOfflineMode) {
        delete wbSkuIndexRef.current[currentSupply.supplier_id];
        skuIndex = await ensureWbSkuIndex(currentSupply.supplier_id);
        hit = skuIndex.get(String(input).trim());
      }

      if (hit) {
        matchedCard = hit.card;
        matchedSize = hit.size;
      }

      // Защита: ШК должен принадлежать поставщику текущей поставки.
      // Если в карточке указан другой supplier_id — товар чужой, не заносим.
      if (matchedCard) {
        const cardSup = String(matchedCard?.supplierId || matchedCard?.supplier_id || matchedCard?.supplierID || '').trim();
        if (cardSup && cardSup !== String(currentSupply.supplier_id)) {
          const otherName = suppliers.find((s: any) => String(s.id) === cardSup)?.name || 'другой поставщик';
          showToast(`Этот ШК принадлежит другому поставщику (${otherName}). Товар не добавлен.`, 'error');
          playScanTone('error');
          return;
        }
      }

      if (matchedCard && matchedSize) {
        const productsIndex = await ensureSupplierProductsIndex(currentSupply.supplier_id);
        const cachedProduct = productsIndex.get(String(input));
        const modelNumbers = await ensureWbModelNumbers();
        const nmId = String(matchedCard?.nmID || matchedCard?.nmId || '').trim();
        const manualModelNumber = nmId ? String(modelNumbers[nmId] || '').trim() : '';

        if (cachedProduct) {
          product = buildFboScanProductCard({ ...cachedProduct, model_number: manualModelNumber }, matchedCard, matchedSize, input);
        } else {
          const colorValue = getWbCharacteristicValue(matchedCard, ['цвет']);

          if (fboOfflineMode) {
            const offlineProduct = {
              id: `offline-product-${currentSupply.supplier_id}-${String(input).trim()}`,
              supplier_id: currentSupply.supplier_id,
              name: String(matchedCard.title || 'Товар'),
              wb_sku: String(matchedCard.nmID || ''),
              barcode: String(input).trim(),
              size: String(matchedSize.techSize || ''),
              color: String(colorValue || ''),
              created_at: new Date().toISOString(),
              model_number: manualModelNumber,
            } as Product;
            product = buildFboScanProductCard(offlineProduct, matchedCard, matchedSize, input);
            productsIndex.set(String(input), product);
          } else {
            const { data: newProd, error: insertError } = await supabase
              .from('products')
              .insert({
                name: matchedCard.title,
                wb_sku: String(matchedCard.nmID || ''),
                barcode: input,
                size: matchedSize.techSize,
                color: colorValue,
                supplier_id: currentSupply.supplier_id,
              })
              .select()
              .single();

            if (!insertError && newProd) {
              product = buildFboScanProductCard({ ...(newProd as Product), model_number: manualModelNumber }, matchedCard, matchedSize, input);
              productsIndex.set(String(input), product);
            }
          }
        }
      }
    } catch (e) {
      console.error('WB cache search error:', e);
    }

    if (!product) {
      showToast('Товар не найден в разделе Товары WB (кэш поставщика). Нажмите «Обновить» в Товары WB.', 'error');
      return;
    }

    const palletHint = await findFboPalletHint(product);
    setFboPalletHint(palletHint);
    if (palletHint) {
      showToast(`${(palletHint.warehouse_name || 'Склад не указан') + ' • '}${(palletHint.supply_name || 'Поставка не указана') + ' • '}Паллета №${palletHint.pallet_number}: ${Number(palletHint.scanned_qty || 0) + 1}/${palletHint.target_qty || 1}. Поставьте коробку туда.`, 'info');
    }

    setScannedItem(product);
    setSupplyStep('HONEST_SIGN');
  };

  const playScanTone = (kind: 'success' | 'error' = 'success') => {
    try {
      const Ctx = (window as any).AudioContext || (window as any).webkitAudioContext;
      if (!Ctx) return;
      if (!scanAudioCtxRef.current) scanAudioCtxRef.current = new Ctx();
      const ctx = scanAudioCtxRef.current;
      if (ctx.state === 'suspended') ctx.resume?.();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.type = kind === 'error' ? 'square' : 'sine';
      osc.frequency.value = kind === 'error' ? 220 : 880;
      gain.gain.setValueAtTime(0.0001, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(kind === 'error' ? 0.15 : 0.12, ctx.currentTime + 0.01);
      gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + 0.10);
      osc.start();
      osc.stop(ctx.currentTime + 0.11);
    } catch {}
  };

  const syncScannedCodesToUnifiedBase = useCallback(async (codes: string[], supplierId?: string) => {
    const normalizedSupplierId = String(supplierId || '').trim();
    const uniqueCodes = Array.from(new Set((codes || []).map((code) => String(code || '').trim()).filter(Boolean)));
    if (!normalizedSupplierId || uniqueCodes.length === 0) return;

    const nowIso = new Date().toISOString();
    const { data: existing, error: existingError } = await supabase
      .from('unified_honest_sign_codes')
      .select('id, code, supplier_id, category')
      .in('code', uniqueCodes);

    if (existingError) throw existingError;

    const existingByCode = new Map<string, any>();
    (existing || []).forEach((row: any) => {
      const code = String(row?.code || '').trim();
      if (code) existingByCode.set(code, row);
    });

    const idsToUpdate: string[] = [];
    const toInsert: Array<{ supplier_id: string; category: string; code: string; file_name: string; status: string; created_at: string }> = [];

    uniqueCodes.forEach((code) => {
      const row = existingByCode.get(code);
      if (!row) {
        toInsert.push({
          supplier_id: normalizedSupplierId,
          category: normalizeHSCategory('Без категории'),
          code,
          file_name: 'Отсканировано',
          status: 'scanned',
          created_at: nowIso,
        });
        return;
      }

      const rowSupplierId = String(row?.supplier_id || '').trim();
      if (!rowSupplierId || rowSupplierId === normalizedSupplierId) {
        if (row?.id) idsToUpdate.push(String(row.id));
      }
    });

    if (idsToUpdate.length > 0) {
      const { error } = await supabase
        .from('unified_honest_sign_codes')
        .update({
          supplier_id: normalizedSupplierId,
          file_name: 'Отсканировано',
          status: 'scanned',
          created_at: nowIso,
        })
        .in('id', idsToUpdate);
      if (error) throw error;
    }

    if (toInsert.length > 0) {
      const { error } = await supabase
        .from('unified_honest_sign_codes')
        .insert(toInsert);
      if (error) throw error;
    }
  }, [normalizeHSCategory]);

  const isCodeAlreadyScannedForSupplier = useCallback(async (code: string, supplierId?: string) => {
    const normalizedCode = String(code || '').trim();
    const normalizedSupplierId = String(supplierId || '').trim();
    if (!normalizedCode || !normalizedSupplierId) return false;

    const { data, error } = await supabase
      .from('unified_honest_sign_codes')
      .select('id')
      .eq('supplier_id', normalizedSupplierId)
      .eq('code', normalizedCode)
      .or('file_name.eq.Отсканировано,status.eq.scanned')
      .limit(1)
      .maybeSingle();

    if (error) throw error;
    return Boolean(data?.id);
  }, []);

  const flushPendingScans = useCallback(async () => {
    if (pendingScansRef.current.length === 0) return;
    const batch = [...pendingScansRef.current];
    pendingScansRef.current = [];

    const { error } = await supabase.from('supply_items').insert(
      batch.map((x) => ({ box_id: x.boxId, product_id: x.productId, honest_sign_code: x.code, scanned_by: x.scannedBy || null }))
    );

    if (error) {
      playScanTone('error');
      showToast('Ошибка пакетного сохранения: ' + error.message, 'error');
      return;
    }

    try {
      await syncScannedCodesToUnifiedBase(batch.map((x) => x.code), currentSupply?.supplier_id);
    } catch (e: any) {
      console.error('Failed to sync FBO scanned codes to unified base', e);
      showToast('ЧЗ сохранён в поставку, но не удалось обновить базу ЧЗ', 'error');
    }

    if (currentBox) fetchBoxItems(currentBox.id);
  }, [currentBox, currentSupply?.supplier_id, syncScannedCodesToUnifiedBase]);

  const handleHonestSignScan = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentBox || !scannedItem) return;

    let code = (honestSignInputRef.current?.value || '').trim();
    if (!code) return;

    if (isScanningRef.current) return;
    isScanningRef.current = true;

    try {
        if (honestSignInputRef.current) honestSignInputRef.current.value = ''; // Clear immediately for speed

        if (/[\p{Script=Cyrillic}]/u.test(code)) {
           code = fixLayout(code);
           showToast('Раскладка исправлена', 'info');
        }

        if (tryHandleWorkerBadge(code)) return;

        if (code.trim() === 'ACTION:NEW_BOX' || code.trim() === 'NEW_BOX' || code.includes('NEW_BOX') || code.includes('ACTION;NEW_BOX')) {
          finishCurrentBoxAndReturn();
          return;
        }

        // Validation: Prevent scanning item barcodes (EAN-8, EAN-13, UPC-12)
        // Honest Sign codes are usually much longer (DataMatrix)
        if ((code.length === 8 || code.length === 12 || code.length === 13) && /^\d+$/.test(code)) {
          playScanTone('error');
          showToast('Это штрихкод товара, а не Честный Знак!', 'error');
          return;
        }

        if (warehouseOfflineEnabled) {
          const scanRow = {
            supply_id: currentSupply?.id,
            supply_name: currentSupply?.name,
            supplier_id: currentSupply?.supplier_id,
            box_id: currentBox.id,
            box_name: currentBox.name,
            product_id: scannedItem.id,
            product_name: scannedItem.name,
            product_barcode: scannedItem.barcode,
            product_size: scannedItem.size,
            product_color: scannedItem.color,
            product_model_number: scannedItem.model_number || '',
            honest_sign_code: code,
            code,
            createdAt: new Date().toISOString(),
          };
          await warehouseOfflineClient.enqueueFboScan(scanRow);
          await checkWarehouseOfflineServer(false);
          playScanTone('success');
          setBoxItems((prev) => ([{ id: 'warehouse-offline-' + Date.now() + '-' + Math.random(), box_id: currentBox.id, product_id: scannedItem.id, honest_sign_code: code, created_at: new Date().toISOString(), deleted_at: null, product: scannedItem } as any, ...(prev || [])]));
          setSupplyStats((prev) => ({ ...prev, items: Number(prev.items || 0) + 1 }));
          showToast('Скан сохранён в локальную очередь ПК', 'success');
          setScannedItem(null);
          setSupplyStep('BOX');
          return;
        }

        if (fboOfflineMode && currentSupply) {
          const session = offlineFboSessionRef.current && offlineFboSessionRef.current.supply_id === currentSupply.id ? offlineFboSessionRef.current : buildEmptyOfflineFboSession(currentSupply);
          const offlineDuplicate = (session.items || []).some((item) => item.honest_sign_code === code);
          if (offlineDuplicate) {
            playScanTone('error');
            showToast('Этот Честный Знак уже добавлен в оффлайн-сессию!', 'error');
            return;
          }
          const newItem: SupplyItem = {
            id: `offline-item-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            box_id: currentBox.id,
            product_id: scannedItem.id,
            honest_sign_code: code,
            created_at: new Date().toISOString(),
            product: scannedItem,
          };
          updateOfflineFboSession((currentSession) => ({ ...currentSession, items: [newItem, ...(currentSession.items || [])] }), currentBox.id);
          playScanTone('success');
          showToast('Товар добавлен в оффлайн-сессию', 'success');
          setScannedItem(null);
          setSupplyStep('BOX');
          return;
        }

        const pendingDuplicate = pendingScansRef.current.some((x) => x.code === code);
        if (pendingDuplicate) {
          playScanTone('error');
          showToast('Этот Честный Знак уже добавлен в очередь!', 'error');
          return;
        }

        // Дубль проверяем по всей истории: и в базе ЧЗ поставщика, и глобально по supply_items.
        const existsInSupplierScannedBase = await isCodeAlreadyScannedForSupplier(code, currentSupply?.supplier_id);
        if (existsInSupplierScannedBase) {
          playScanTone('error');
          showToast('Этот Честный Знак уже есть в базе отсканированных ЧЗ этого поставщика!', 'error');
          return;
        }

        const { data: existing } = await supabase.from('supply_items').select('id').eq('honest_sign_code', code).maybeSingle();
        if (existing) {
          playScanTone('error');
          showToast('Этот Честный Знак уже отсканирован!', 'error');
          return;
        }

        pendingScansRef.current.push({ boxId: currentBox.id, productId: scannedItem.id, code, scannedBy: resolveScannerId() });
        playScanTone('success');
        setBoxItems((prev) => ([{ id: `pending-${Date.now()}-${Math.random()}`, box_id: currentBox.id, product_id: scannedItem.id, honest_sign_code: code, created_at: new Date().toISOString(), deleted_at: null, product: scannedItem } as any, ...(prev || [])]));
        setSupplyStats((prev) => ({ ...prev, items: Number(prev.items || 0) + 1 }));

        if (flushScansTimeoutRef.current) {
          window.clearTimeout(flushScansTimeoutRef.current);
        }

        flushScansTimeoutRef.current = window.setTimeout(() => {
          flushPendingScans().catch((err) => {
            console.error('Batch flush failed', err);
          });
        }, 90);

        showToast('Товар добавлен', 'success');
        setScannedItem(null);
        setSupplyStep('BOX');
    } finally {
        isScanningRef.current = false;
    }
  };

  useEffect(() => {
    return () => {
      if (flushScansTimeoutRef.current) {
        window.clearTimeout(flushScansTimeoutRef.current);
      }
      if (offlineFboSessionWriteTimeoutRef.current) {
        window.clearTimeout(offlineFboSessionWriteTimeoutRef.current);
      }
      if (offlineFboStatsRefreshTimeoutRef.current) {
        window.clearTimeout(offlineFboStatsRefreshTimeoutRef.current);
      }
      flushPendingScans().catch(() => undefined);
    };
  }, [flushPendingScans]);

  const handleDeleteBox = async (boxId: string) => {
    if (!await confirmDialog('Вы уверены, что хотите удалить эту коробку?')) return;
    try {
      if (warehouseOfflineEnabled) {
        const snapshot = await getWarehouseOfflineSnapshotOrEmpty();
        const box = (snapshot.fboBoxes || []).find((row: any) => String(row?.id || '') === String(boxId));
        const nextSnapshot = {
          ...snapshot,
          fboBoxes: (snapshot.fboBoxes || []).filter((row: any) => String(row?.id || '') !== String(boxId)),
        };
        await saveWarehouseOfflineSnapshotState(nextSnapshot);
        await warehouseOfflineClient.deleteFboScansByBox(boxId).catch(() => ({ ok: true, deleted: 0 }));
        if (currentBox?.id === boxId) {
          setCurrentBox(null);
          setSupplyStep('SUPPLY');
          setBoxItems([]);
        }
        if (currentSupply) {
          await fetchBoxesList(currentSupply.id);
          await fetchSupplyStats(currentSupply.id);
        }
        logAction('Удаление коробки', `Удалена коробка (offline): ${box?.name || boxId}`, currentEmployee?.id);
        showToast('Offline-коробка удалена' + (box?.name ? `: ${box.name}` : ''), 'success');
        return;
      }

      if (fboOfflineMode && currentSupply) {
        const offBox = (offlineFboSessionRef.current?.boxes || []).find((b: any) => b.id === boxId);
        updateOfflineFboSession((session) => ({
          ...session,
          boxes: (session.boxes || []).filter((box) => box.id !== boxId),
          items: (session.items || []).filter((item) => item.box_id !== boxId),
        }));
        if (currentBox?.id === boxId) {
          setCurrentBox(null);
          setSupplyStep('SUPPLY');
          setBoxItems([]);
        }
        logAction('Удаление коробки', `Удалена коробка (offline): ${offBox?.name || boxId}`, currentEmployee?.id);
        showToast('Оффлайн-коробка удалена', 'success');
        return;
      }

      const { data: box } = await supabase.from('boxes').select('name').eq('id', boxId).single();
      const { error } = await supabase.from('boxes').update({ deleted_at: new Date().toISOString() }).eq('id', boxId);
      if (error) throw error;

      await logAction('Удаление коробки', `Удалена коробка: ${box?.name || 'Без названия'}`, currentEmployee?.id);

      if (currentSupply) fetchBoxesList(currentSupply.id);
      showToast('Коробка удалена', 'success');
    } catch (e: any) {
      showToast('Ошибка удаления коробки: ' + e.message, 'error');
    }
  };

