  useEffect(() => {
    const runAutoScheduleNotify = async () => {
      if (String(currentEmployee?.role || '').toLowerCase() !== 'admin') return;
      const token = String((telegramBotToken || '').trim());
      if (!token) return;
      let dates: string[] = [];
      try {
        const { data } = await supabase.from('app_settings').select('value').eq('key', 'cw_schedule_auto_notify_dates_v1').maybeSingle();
        const parsed = data?.value ? (typeof data.value === 'string' ? JSON.parse(data.value) : data.value) : [];
        dates = Array.isArray(parsed) ? parsed.map((x: any) => String(x)) : [];
      } catch { return; }
      const today = new Date();
      const dayOfMonth = today.getDate();
      const days = dates.map((d) => Number(String(d).replace(/\D+/g, ''))).filter((n) => Number.isFinite(n) && n >= 1 && n <= 31);
      if (!days.includes(dayOfMonth)) return;

      const todayStr = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;
      const sentKey = `cw_schedule_auto_notify_sent_v1:${todayStr}`;
      const { data: sentRow } = await supabase.from('app_settings').select('value').eq('key', sentKey).maybeSingle();
      if (sentRow?.value) return;

      const targets = (employees || [])
        .filter((e: any) => String(e.role || '').toLowerCase() !== 'admin' && String(e.login || '').toLowerCase() !== 'admin')
        .filter((e: any) => isButtonVisibleForEmployee('cw_schedule_notify_pick', String(e.id)))
        .map((e: any) => ({ id: e.id, chatId: String(e.telegram_chat_id || '').trim() }))
        .filter((x: any) => x.chatId);

      let sent = 0;
      for (const t of targets) {
        await telegramService.sendMessage(token, t.chatId, 'Пожалуйста, заполните график рабочих и выходных дней.');
        sent += 1;
      }
      await supabase.from('app_settings').upsert([{ key: sentKey, value: JSON.stringify({ sent, at: new Date().toISOString() }) }], { onConflict: 'key' });
    };
    runAutoScheduleNotify().catch(() => {});
  }, [currentEmployee, telegramBotToken, employees, isButtonVisibleForEmployee]);

