  const createUploadedReportShareLink = async () => {
    if (!uploadedReportAnalytics.length || !uploadedReportSummary) {
      showToast('Сначала загрузите отчет и постройте аналитику', 'error');
      return;
    }

    try {
      setUploadedShareLoading(true);
      const token = (globalThis.crypto?.randomUUID?.() || `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`).replace(/-/g, '');
      const supplier = (suppliers || []).find((s: any) => String(s?.id) === String(uploadedSelectedSupplierId));
      const summaryNow = uploadedSummaryForView || uploadedReportSummary;
      const rowsNow = sortedFilteredUploadedAnalytics || uploadedReportAnalytics || [];
      const taxRate = getUploadedTaxRate(summaryNow);
      const taxSum = Number(summaryNow?.sales_net || 0) * taxRate;
      const headlineProfit = getUploadedHeadlineProfit(summaryNow);
      const extraCosts = Number(uploadedExtraCosts || 0);

      const payload = {
        title: `Аналитика WB${supplier?.name ? ` - ${supplier.name}` : ''}`,
        supplier_id: uploadedSelectedSupplierId || null,
        supplier_name: supplier?.name || null,
        period_start: summaryNow?.period_start || null,
        period_end: summaryNow?.period_end || null,
        summary: {
          ...(summaryNow || {}),
          supplier_id: uploadedSelectedSupplierId || null,
          supplier_name: supplier?.name || null,
          tax_rate: taxRate,
          tax_sum: taxSum,
          extra_costs: extraCosts,
          headline_profit: headlineProfit - extraCosts,
          items_table: Number(rowsNow.length || 0),
        },
        analytics: (rowsNow || []).map((r: any) => {
          const soldQty = Number(r?.sold_qty || 0);
          const costVal = Number(getUploadedCostValue(r) || 0);
          const baseProfit = (soldQty > 0 ? (Number(r?.to_pay_total || 0) / soldQty) - costVal : 0) * soldQty;
          const taxValue = Number(r?.sales_net || 0) * getUploadedTaxRate(summaryNow);
          const profitTotal = baseProfit - taxValue;
          const avgProfit = soldQty > 0 ? profitTotal / soldQty : 0;
          const photoCandidates = getUploadedPhotoCandidates(String(r?.code || ''));
          return {
            ...r,
            cost: costVal,
            avg_profit: avgProfit,
            profit_total: profitTotal,
            photo_url: photoCandidates[0] || '',
            photo_candidates: photoCandidates,
          };
        }),
        visible_cols: uploadedVisibleCols || {},
        created_at: new Date().toISOString(),
      };

      const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString();
      const { error } = await supabase.from('analytics_shared_reports').insert({
        token,
        payload_json: payload,
        expires_at: expiresAt,
      });
      if (error) throw error;

      const link = `${window.location.origin}/shared/${token}`;
      await loadUploadedShareLinks();
      try { await navigator.clipboard.writeText(link); } catch {}
      showToast('Ссылка на отчёт создана и скопирована', 'success');
      window.prompt('Ссылка на отчёт (откроется без авторизации):', link);
    } catch (e: any) {
      console.error('createUploadedReportShareLink error', e);
      showToast(e?.message || 'Не удалось создать ссылку', 'error');
    } finally {
      setUploadedShareLoading(false);
    }
  };

  const loadUploadedShareLinks = async () => {
    try {
      setUploadedShareLinksLoading(true);
      const { data, error } = await supabase
        .from('analytics_shared_reports')
        .select('id, token, payload_json, expires_at, created_at')
        .order('created_at', { ascending: false })
        .limit(500);
      if (error) throw error;

      const nowTs = Date.now();
      const selectedSupplier = String(uploadedSelectedSupplierId || '').trim();

      const activeOnly = (Array.isArray(data) ? data : []).filter((x: any) => {
        const exp = x?.expires_at ? new Date(x.expires_at).getTime() : null;
        const isActive = !exp || Number.isNaN(exp) || exp > nowTs;
        if (!isActive) return false;

        if (!selectedSupplier) return true;
        const payloadSupplierId = String(x?.payload_json?.summary?.supplier_id || x?.payload_json?.supplier_id || '').trim();
        return payloadSupplierId === selectedSupplier;
      });

      const visible = activeOnly.filter((x: any) => {
        const keyById = `id:${String(x?.id || '')}`;
        const keyByToken = `token:${String(x?.token || '')}`;
        return !uploadedShareHiddenKeys[keyById] && !uploadedShareHiddenKeys[keyByToken];
      });
      setUploadedShareLinks(visible);
    } catch (e) {
      console.error('loadUploadedShareLinks error', e);
      setUploadedShareLinks([]);
    } finally {
      setUploadedShareLinksLoading(false);
    }
  };

  const disableUploadedShareLink = async (id: string, token?: string) => {
    if (!id && !token) return;
    const label = token ? `${window.location.origin}/shared/${token}` : 'эту ссылку';
    const ok = await confirmDialog({ title: 'Отключить ссылку', tone: 'warning', confirmText: 'Отключить', message: label });
    if (!ok) return;
    try {
      const nowIso = new Date().toISOString();
      setUploadedShareHiddenKeys((prev) => ({
        ...prev,
        ...(id ? { [`id:${String(id)}`]: true } : {}),
        ...(token ? { [`token:${String(token)}`]: true } : {}),
      }));
      let q = supabase
        .from('analytics_shared_reports')
        .update({ expires_at: nowIso })
        .select('id, token');
      q = token ? q.eq('token', token) : q.eq('id', id);
      const { error } = await q;
      if (error) throw error;

      setUploadedShareLinks((prev: any[]) =>
        (Array.isArray(prev) ? prev : []).map((x: any) => {
          const byId = id && String(x?.id) === String(id);
          const byToken = token && String(x?.token) === String(token);
          return byId || byToken ? { ...x, expires_at: nowIso } : x;
        }),
      );
      await loadUploadedShareLinks();
      showToast('Ссылка отключена', 'success');
    } catch (e: any) {
      console.error('disableUploadedShareLink error', e);
      showToast(e?.message || 'Не удалось отключить ссылку', 'error');
    }
  };

  const deleteUploadedShareLink = async (id: string, token?: string) => {
    if (!id && !token) return;
    const label = token ? `${window.location.origin}/shared/${token}` : 'эту ссылку';
    const ok = await confirmDialog(`Удалить ссылку?\n${label}`);
    if (!ok) return;
    try {
      setUploadedShareHiddenKeys((prev) => ({
        ...prev,
        ...(id ? { [`id:${String(id)}`]: true } : {}),
        ...(token ? { [`token:${String(token)}`]: true } : {}),
      }));

      let deleteQ = supabase
        .from('analytics_shared_reports')
        .delete()
        .select('id, token');
      deleteQ = token ? deleteQ.eq('token', token) : deleteQ.eq('id', id);
      const { error: deleteError } = await deleteQ;

      // Fallback for strict RLS: soft-delete by expiring link now.
      if (deleteError) {
        const nowIso = new Date().toISOString();
        let updateQ = supabase
          .from('analytics_shared_reports')
          .update({ expires_at: nowIso })
          .select('id, token');
        updateQ = token ? updateQ.eq('token', token) : updateQ.eq('id', id);
        const { error: updateError } = await updateQ;
        if (updateError) throw updateError;
      }

      setUploadedShareLinks((prev: any[]) =>
        (Array.isArray(prev) ? prev : []).filter((x: any) => {
          const byId = id && String(x?.id) === String(id);
          const byToken = token && String(x?.token) === String(token);
          return !(byId || byToken);
        }),
      );
      await loadUploadedShareLinks();
      showToast('Ссылка удалена', 'success');
    } catch (e: any) {
      console.error('deleteUploadedShareLink error', e);
      showToast(e?.message || 'Не удалось удалить ссылку', 'error');
    }
  };



  // Read advertising stats from our DB snapshot (filled by the wb-adv-sync edge
  // function on a schedule). Instant — no WB API call, no rate limits.
  const loadAdsApiData = async (fromArg?: string, toArg?: string) => {
    const from = fromArg || adsApiFrom;
    const to = toArg || adsApiTo;
    if (!adsApiSupplierId) { setAdsApiError('Выберите поставщика'); return; }
    if (!from || !to) { setAdsApiError('Укажите период'); return; }
    setAdsApiLoading(true); setAdsApiError(null);
    try {
      const { data, error } = await supabase
        .from('wb_adv_stats_daily')
        .select('advert_id, date, campaign_name, views, clicks, sum, atbs, orders, shks, sum_price')
        .eq('supplier_id', adsApiSupplierId)
        .gte('date', from).lte('date', to);
      if (error) throw error;
      const rows = data || [];
      const t = { views: 0, clicks: 0, sum: 0, atbs: 0, orders: 0, shks: 0, revenue: 0 };
      const dayMap = new Map<string, { spend: number; clicks: number; orders: number; revenue: number; views: number }>();
      const campMap = new Map<number, any>();
      rows.forEach((r: any) => {
        const sp = Number(r.sum || 0), rev = Number(r.sum_price || 0);
        t.views += Number(r.views || 0); t.clicks += Number(r.clicks || 0); t.sum += sp;
        t.atbs += Number(r.atbs || 0); t.orders += Number(r.orders || 0); t.shks += Number(r.shks || 0); t.revenue += rev;
        const e = dayMap.get(r.date) || { spend: 0, clicks: 0, orders: 0, revenue: 0, views: 0 };
        e.spend += sp; e.clicks += Number(r.clicks || 0); e.orders += Number(r.orders || 0); e.revenue += rev; e.views += Number(r.views || 0);
        dayMap.set(r.date, e);
        const c = campMap.get(r.advert_id) || { id: r.advert_id, name: r.campaign_name || `#${r.advert_id}`, views: 0, clicks: 0, sum: 0, atbs: 0, orders: 0, revenue: 0 };
        c.views += Number(r.views || 0); c.clicks += Number(r.clicks || 0); c.sum += sp; c.atbs += Number(r.atbs || 0); c.orders += Number(r.orders || 0); c.revenue += rev;
        if (r.campaign_name) c.name = r.campaign_name;
        campMap.set(r.advert_id, c);
      });
      const daily = Array.from(dayMap.entries()).sort((a, b) => (a[0] < b[0] ? -1 : 1)).map(([date, v]) => ({ date, ...v }));
      const campaigns = Array.from(campMap.values()).sort((a, b) => b.sum - a.sum);
      setAdsApiData({ totals: t, daily, campaigns, count: campaigns.length });
      // last sync time
      try {
        const { data: log } = await supabase.from('wb_adv_sync_log').select('ran_at').eq('supplier_id', adsApiSupplierId).order('ran_at', { ascending: false }).limit(1).maybeSingle();
        if (log?.ran_at) setAdsApiLastSync(new Date(log.ran_at).toLocaleString('ru-RU'));
      } catch {}
      if (!rows.length) setAdsApiError('Нет данных за период. Нажмите «Синхронизировать с WB», чтобы загрузить из кабинета.');
    } catch (e: any) {
      console.error('loadAdsApiData error', e);
      setAdsApiError(e?.message || 'Ошибка чтения данных');
    } finally {
      setAdsApiLoading(false);
    }
  };

  // Trigger a server-side sync (edge function) for the selected supplier, then reload from DB.
  const syncAdsApiNow = async () => {
    if (!adsApiSupplierId) { setAdsApiError('Выберите поставщика'); return; }
    setAdsApiSyncing(true); setAdsApiError(null);
    // Native fetch (NOT supabase client) so we bypass the client's 35s resilient
    // timeout + false "connection issue" banner; sync can run up to ~2.5 min.
    const base = (import.meta as any).env?.VITE_SUPABASE_URL || 'https://blygwkxjogmioebutiwn.supabase.co';
    const key = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY || 'sb_publishable_kSk_B3Y6eN5P9sCVk67-cg_uSGedHJX';
    // One 30-day window in a single SHORT request (stays well under the ~150s edge limit).
    const iso = (d: Date) => d.toISOString().slice(0, 10);
    const today = new Date();
    const begin = new Date(today); begin.setUTCDate(begin.getUTCDate() - 30);
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 140000);
    try {
      const r = await fetch(`${base}/functions/v1/wb-adv-sync`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', apikey: key, Authorization: `Bearer ${key}` },
        body: JSON.stringify({ supplier_id: adsApiSupplierId, begin: iso(begin), end: iso(today) }),
        signal: ctrl.signal,
      });
      const data = await r.json().catch(() => ({}));
      if (!r.ok || data?.error) throw new Error(data?.error || `HTTP ${r.status}`);
      const res = (data?.results || [])[0];
      if (res && !res.ok) throw new Error(res.message || 'Ошибка синхронизации');
      showToast(`Синхронизация завершена${res ? `: кампаний ${res.campaigns}` : ''}`, 'success');
      await loadAdsApiData();
    } catch (e: any) {
      console.error('syncAdsApiNow error', e);
      const msg = e?.name === 'AbortError' ? 'Синхронизация идёт дольше обычного. Данные дольются в фоне — нажмите «Показать» через минуту.' : 'Синхронизация: ' + (e?.message || 'ошибка. Проверьте токен «Продвижение».');
      setAdsApiError(msg);
    } finally {
      clearTimeout(timer);
      setAdsApiSyncing(false);
    }
  };

  // Загрузка ключей/кластеров одной кампании (живой запрос к WB через edge).
  const loadAdsApiKeywords = async (advertId: number, name: string) => {
    if (!adsApiSupplierId) { setAdsApiError('Выберите поставщика'); return; }
    setAdsApiKwFor({ id: advertId, name });
    setAdsApiKwLoading(true); setAdsApiKwData(null); setAdsApiKwNote('');
    const base = (import.meta as any).env?.VITE_SUPABASE_URL || 'https://blygwkxjogmioebutiwn.supabase.co';
    const key = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY || 'sb_publishable_kSk_B3Y6eN5P9sCVk67-cg_uSGedHJX';
    const iso = (d: Date) => d.toISOString().slice(0, 10);
    const to = adsApiTo || iso(new Date());
    const from = adsApiFrom || iso(new Date(Date.now() - 29 * 86400000));
    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 120000);
    try {
      const r = await fetch(`${base}/functions/v1/wb-adv-keywords`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', apikey: key, Authorization: `Bearer ${key}` },
        body: JSON.stringify({ supplier_id: adsApiSupplierId, advert_id: advertId, from, to }),
        signal: ctrl.signal,
      });
      const data = await r.json().catch(() => ({}));
      if (!r.ok || data?.error) throw new Error(data?.error || `HTTP ${r.status}`);
      const kws = data?.keywords || [];
      setAdsApiKwData(kws);
      if (!kws.length) {
        setAdsApiKwNote(data?.kwErr === '429'
          ? 'WB временно ограничил запросы (лимит ~5/мин). Повторите через минуту.'
          : 'WB не вернул поисковые фразы по этой кампании за период (нет кластеров с >100 показов или поискового размещения).');
      }
    } catch (e: any) {
      setAdsApiKwData([]);
      setAdsApiKwNote(e?.name === 'AbortError' ? 'Долгий ответ WB — повторите.' : 'Ошибка: ' + (e?.message || 'не удалось загрузить'));
    } finally {
      clearTimeout(timer);
      setAdsApiKwLoading(false);
    }
  };

  const adsApiPreset = (kind: 'today' | 'yesterday' | '7' | '30') => {
    const iso = (d: Date) => d.toISOString().slice(0, 10);
    const today = new Date();
    let from: string, to: string;
    if (kind === 'today') { from = to = iso(today); }
    else if (kind === 'yesterday') { const y = new Date(today); y.setDate(y.getDate() - 1); from = to = iso(y); }
    else { const n = kind === '7' ? 6 : 29; const s = new Date(today); s.setDate(s.getDate() - n); from = iso(s); to = iso(today); }
    setAdsApiFrom(from); setAdsApiTo(to);
    if (adsApiSupplierId) void loadAdsApiData(from, to);
  };


  const uploadedHistoryMonthNames = ['Январь', 'Февраль', 'Март', 'Апрель', 'Май', 'Июнь', 'Июль', 'Август', 'Сентябрь', 'Октябрь', 'Ноябрь', 'Декабрь'];

  const uploadedHistoryYears = useMemo(() => {
    const years = new Set<number>();
    (uploadedHistory || []).forEach((h: any) => {
      const base = h?.summary_json?.period_start || h?.summary_json?.period_end || h?.created_at;
      const d = new Date(base || '');
      if (!Number.isNaN(d.getTime())) years.add(d.getFullYear());
    });
    return Array.from(years).sort((a, b) => a - b);
  }, [uploadedHistory]);

  const uploadedHistoryGrouped = useMemo(() => {
    const byMonth = new Map<number, any[]>();
    (uploadedHistory || []).forEach((h: any) => {
      const base = h?.summary_json?.period_start || h?.summary_json?.period_end || h?.created_at;
      const d = new Date(base || '');
      if (Number.isNaN(d.getTime())) return;
      if (uploadedHistoryYear != null && d.getFullYear() !== uploadedHistoryYear) return;
      const m = d.getMonth();
      if (!byMonth.has(m)) byMonth.set(m, []);
      byMonth.get(m)!.push(h);
    });
    const groups = Array.from(byMonth.entries()).sort((a, b) => a[0] - b[0]);
    groups.forEach(([, items]) => {
      items.sort((x: any, y: any) => {
        const dx = new Date(x?.summary_json?.period_start || x?.created_at || 0).getTime();
        const dy = new Date(y?.summary_json?.period_start || y?.created_at || 0).getTime();
        return dx - dy;
      });
    });
    return groups;
  }, [uploadedHistory, uploadedHistoryYear]);

  const uploadedHistorySelectedCount = useMemo(() => Object.values(uploadedHistorySelectedIds || {}).filter(Boolean).length, [uploadedHistorySelectedIds]);

  const getTaxRateByYear = (y: number) => {
    if (y === 2025) return 0.01;
    if (y === 2026) return 0.06;
    return 0;
  };

  const getAnalyticsCostsKey = (supplierId?: string | null) => `analytics_costs_v1:${String(supplierId || 'global')}`;
  const visibleUploadedAnalyticsSuppliers = (uploadedAnalyticsSuppliers || []).filter((s: any) => String(currentEmployee?.role || '').toLowerCase() === 'admin' || String(s?.name || '').trim() !== 'ИП Власенко И А');

  const getUploadedTaxRate = (summary: any) => {
    if (uploadedTaxRateOverride != null) return uploadedTaxRateOverride;
    const base = summary?.period_start || summary?.period_end || summary?.created_at || '';
    const y = new Date(base).getFullYear();
    return getTaxRateByYear(y);
  };
  const getUploadedTaxValue = (summary: any) => {
    return Number(summary?.sales_net || 0) * getUploadedTaxRate(summary);
  };
  const getCurrentUploadedTaxRate = () => getUploadedTaxRate(uploadedReportSummary);

  const formatAdsCell = (value: any) => {
    if (value === null || value === undefined || value === '') return '-';
    const n = Number(String(value).replace(/\s/g, '').replace(',', '.'));
    if (Number.isFinite(n) && String(value).trim() !== '') return n.toLocaleString('ru-RU', { maximumFractionDigits: 2 });
    return String(value);
  };

  const getAdsSheetViewRows = (sheetKey: string, sheet: { columns: string[]; rows: any[] }) => {
    const q = String(adsSheetFilters[sheetKey] || '').trim().toLowerCase();
    const sort = adsSheetSorts[sheetKey];

    let rows = Array.isArray(sheet.rows) ? [...sheet.rows] : [];

    if (q) {
      rows = rows.filter((row: any) =>
        sheet.columns.some((col) => String(row?.[col] ?? '').toLowerCase().includes(q)),
      );
    }

    if (sort?.col) {
      rows.sort((a: any, b: any) => {
        const av = a?.[sort.col];
        const bv = b?.[sort.col];
        const an = Number(String(av ?? '').replace(/\s/g, '').replace(',', '.'));
        const bn = Number(String(bv ?? '').replace(/\s/g, '').replace(',', '.'));
        let cmp = 0;
        if (Number.isFinite(an) && Number.isFinite(bn)) cmp = an - bn;
        else cmp = String(av ?? '').localeCompare(String(bv ?? ''), 'ru', { numeric: true });
        return sort.dir === 'asc' ? cmp : -cmp;
      });
    }

    return rows;
  };

  const normalizeAdsKey = (v: any) => String(v || '').toLowerCase().replace(/\s+/g, '').replace(/[._-]+/g, '');
  const normalizeNm = (v: any) => String(v ?? '').replace(/\s+/g, '').replace(/[^0-9a-zA-Zа-яА-Я_-]/g, '');
  const toAdsNum = (v: any) => {
    const s = String(v ?? '').replace(/\s/g, '').replace(',', '.');
    const n = Number(s);
    return Number.isFinite(n) ? n : 0;
  };
  const findAdsCol = (columns: string[], aliases: string[]) => {
    const normalizedColumns = columns.map((c) => ({ raw: c, n: normalizeAdsKey(c) }));
    const aliasNorm = aliases.map(normalizeAdsKey);

    const exact = normalizedColumns.find((c) => aliasNorm.includes(c.n));
    if (exact) return exact.raw;

    const partial = normalizedColumns.find((c) => aliasNorm.some((a) => c.n.includes(a) || a.includes(c.n)));
    return partial?.raw || '';
  };

  const adsUnified = React.useMemo(() => {
    const columnsSet = new Set<string>(['__sheet']);
    const rows: any[] = [];

    (adsAnalyticsSheets || []).forEach((sheet, idx) => {
      (sheet.columns || []).forEach((c) => columnsSet.add(c));
      (sheet.rows || []).forEach((r: any) => rows.push({ __sheet: sheet.name || `Лист ${idx + 1}`, ...r }));
    });

    const columns = Array.from(columnsSet);
    const q = String(adsUnifiedFilter || '').trim().toLowerCase();
    let viewRows = [...rows];

    if (q) {
      viewRows = viewRows.filter((row) =>
        columns.some((col) => String(row?.[col] ?? '').toLowerCase().includes(q)),
      );
    }

    if (adsUnifiedSort?.col) {
      const col = adsUnifiedSort.col;
      viewRows.sort((a: any, b: any) => {
        const av = a?.[col];
        const bv = b?.[col];
        const an = Number(String(av ?? '').replace(/\s/g, '').replace(',', '.'));
        const bn = Number(String(bv ?? '').replace(/\s/g, '').replace(',', '.'));
        let cmp = 0;
        if (Number.isFinite(an) && Number.isFinite(bn)) cmp = an - bn;
        else cmp = String(av ?? '').localeCompare(String(bv ?? ''), 'ru', { numeric: true });
        return adsUnifiedSort.dir === 'asc' ? cmp : -cmp;
      });
    }

    return { columns, rows, viewRows };
  }, [adsAnalyticsSheets, adsUnifiedFilter, adsUnifiedSort]);

  const adsKpi = React.useMemo(() => {
    const cols = adsUnified.columns || [];
    const showsCol = findAdsCol(cols, ['показы', 'просмотры', 'impressions', 'shows', 'views']);
    const clicksCol = findAdsCol(cols, ['клики', 'clicks', 'click']);
    const spendCol = findAdsCol(cols, ['затраты,rub', 'затраты', 'расход', 'spend', 'cost']);
    const ordersCol = findAdsCol(cols, ['заказанныетовары,шт.', 'заказы', 'orders', 'order']);
    const revenueCol = findAdsCol(cols, ['заказовнасумму,rub', 'выручка', 'продажи', 'revenue', 'sales']);

    const rows = adsUnified.rows || [];
    const shows = rows.reduce((s, r) => s + toAdsNum(r?.[showsCol]), 0);
    const clicks = rows.reduce((s, r) => s + toAdsNum(r?.[clicksCol]), 0);
    const spend = rows.reduce((s, r) => s + toAdsNum(r?.[spendCol]), 0);
    const orders = rows.reduce((s, r) => s + toAdsNum(r?.[ordersCol]), 0);
    const revenue = rows.reduce((s, r) => s + toAdsNum(r?.[revenueCol]), 0);

    const ctr = shows > 0 ? (clicks / shows) * 100 : 0;
    const cpc = clicks > 0 ? spend / clicks : 0;
    const cpo = orders > 0 ? spend / orders : 0;
    const cr = clicks > 0 ? (orders / clicks) * 100 : 0;
    const drr = revenue > 0 ? (spend / revenue) * 100 : 0;
    const romi = spend > 0 ? ((revenue - spend) / spend) * 100 : 0;
    return { shows, clicks, spend, orders, revenue, ctr, cpc, cpo, cr, drr, romi };
  }, [adsUnified]);

  const adsByNm = React.useMemo(() => {
    const cols = adsUnified.columns || [];
    const nmCol = findAdsCol(cols, ['номенклатура', 'номерноменклатуры', 'артикулwb', 'nmid', 'nm_id', 'артикул', 'sku']);
    if (!nmCol) return [] as any[];

    const showsCol = findAdsCol(cols, ['показы', 'просмотры', 'impressions', 'shows', 'views']);
    const clicksCol = findAdsCol(cols, ['клики', 'clicks']);
    const spendCol = findAdsCol(cols, ['затраты,rub', 'затраты', 'расход', 'spend', 'cost']);
    const ordersCol = findAdsCol(cols, ['заказанныетовары,шт.', 'заказы', 'orders']);
    const revenueCol = findAdsCol(cols, ['заказовнасумму,rub', 'выручка', 'продажи', 'revenue', 'sales']);

    const grouped = new Map<string, any>();
    (adsUnified.rows || []).forEach((r: any) => {
      const nm = normalizeNm(r?.[nmCol]);
      if (!nm) return;

      const cur = grouped.get(nm) || { nm, shows: 0, clicks: 0, spend: 0, orders: 0, revenue: 0 };
      cur.shows += toAdsNum(r?.[showsCol]);
      cur.clicks += toAdsNum(r?.[clicksCol]);
      cur.spend += toAdsNum(r?.[spendCol]);
      cur.orders += toAdsNum(r?.[ordersCol]);
      cur.revenue += toAdsNum(r?.[revenueCol]);
      grouped.set(nm, cur);
    });

    return Array.from(grouped.values())
      .map((x: any) => {
        const ctr = x.shows > 0 ? (x.clicks / x.shows) * 100 : 0;
        const cpc = x.clicks > 0 ? x.spend / x.clicks : 0;
        const drr = x.revenue > 0 ? (x.spend / x.revenue) * 100 : 0;
        const romi = x.spend > 0 ? ((x.revenue - x.spend) / x.spend) * 100 : 0;
        return { ...x, ctr, cpc, drr, romi };
      })
      .sort((a: any, b: any) => b.revenue - a.revenue);
  }, [adsUnified]);

  const adsByNmSorted = React.useMemo(() => {
    const { field, dir } = adsNmSort; const mul = dir === 'asc' ? 1 : -1;
    return [...adsByNm].sort((a: any, b: any) => {
      if (field === 'nm') return String(a.nm).localeCompare(String(b.nm), 'ru') * mul;
      return ((a[field] || 0) - (b[field] || 0)) * mul;
    });
  }, [adsByNm, adsNmSort]);
  const adsNmSortBtn = (field: string) => () => setAdsNmSort((p) => ({ field, dir: p.field === field && p.dir === 'desc' ? 'asc' : 'desc' }));
  const adsNmArw = (field: string) => adsNmSort.field === field ? (adsNmSort.dir === 'asc' ? ' ▲' : ' ▼') : '';

  // Visualisation data for the Ads dashboard: daily dynamics, keyword breakdown,
  // and the impressions→clicks→carts→orders funnel.
  const adsViz = React.useMemo(() => {
    const sheets = adsAnalyticsSheets || [];
    const toISO = (raw: any): string | null => {
      const s = String(raw ?? '').trim();
      if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
      const m = s.match(/(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{4})/);
      if (m) return `${m[3]}-${m[2].padStart(2, '0')}-${m[1].padStart(2, '0')}`;
      return null;
    };
    // Daily spend + clicks (from any sheet that has a date column).
    const dayMap = new Map<string, { spend: number; clicks: number }>();
    sheets.forEach((sh) => {
      const cols = sh.columns || [];
      const dateCol = findAdsCol(cols, ['дата', 'date']);
      if (!dateCol) return;
      const spendCol = findAdsCol(cols, ['затраты,rub', 'затраты', 'расход', 'spend', 'cost']);
      const clicksCol = findAdsCol(cols, ['клики', 'clicks']);
      (sh.rows || []).forEach((r: any) => {
        const d = toISO(r?.[dateCol]); if (!d) return;
        const e = dayMap.get(d) || { spend: 0, clicks: 0 };
        e.spend += toAdsNum(r?.[spendCol]); e.clicks += toAdsNum(r?.[clicksCol]); dayMap.set(d, e);
      });
    });
    const daily = Array.from(dayMap.entries()).filter(([d]) => /^\d{4}/.test(d)).sort((a, b) => (a[0] < b[0] ? -1 : 1)).map(([date, v]) => ({ date, ...v }));

    // Keyword breakdown (sheet with a phrase column). Skip rows that are pure
    // numeric ids (those are nmIDs, not search phrases).
    const kwSheet = sheets.find((sh) => findAdsCol(sh.columns || [], ['ключеваяфраза', 'фраза', 'keyword', 'запрос']));
    const kwMap = new Map<string, { spend: number; clicks: number }>();
    if (kwSheet) {
      const cols = kwSheet.columns || [];
      const fCol = findAdsCol(cols, ['ключеваяфраза', 'фраза', 'keyword', 'запрос']);
      const sCol = findAdsCol(cols, ['затраты,rub', 'затраты', 'расход']);
      const cCol = findAdsCol(cols, ['клики', 'clicks']);
      (kwSheet.rows || []).forEach((r: any) => {
        const f = String(r?.[fCol] || '').trim();
        if (!f || /^\d+$/.test(f)) return;
        const e = kwMap.get(f) || { spend: 0, clicks: 0 };
        e.spend += toAdsNum(r?.[sCol]); e.clicks += toAdsNum(r?.[cCol]); kwMap.set(f, e);
      });
    }
    const keywords = Array.from(kwMap.entries())
      .map(([phrase, v]) => ({ phrase, ...v, cpc: v.clicks ? v.spend / v.clicks : 0 }))
      .sort((a, b) => b.spend - a.spend);
    const kwSpendTotal = keywords.reduce((s, k) => s + k.spend, 0);
    const kwClicksTotal = keywords.reduce((s, k) => s + k.clicks, 0);
    const avgCpc = kwClicksTotal > 0 ? kwSpendTotal / kwClicksTotal : 0;
    // «Слив»: расход есть, кликов нет. «Дорогие»: CPC заметно выше среднего.
    const wasted = keywords.filter((k) => k.spend > 0 && k.clicks === 0).sort((a, b) => b.spend - a.spend);
    const expensive = keywords.filter((k) => k.clicks >= 1 && avgCpc > 0 && k.cpc > avgCpc * 1.15).sort((a, b) => b.cpc - a.cpc);
    const wastedSum = wasted.reduce((s, k) => s + k.spend, 0);
    // Донат: топ-6 фраз + «прочее».
    const donutTop = keywords.slice(0, 6).map((k) => ({ label: k.phrase, value: k.spend }));
    const donutRest = keywords.slice(6).reduce((s, k) => s + k.spend, 0);
    const donut = donutRest > 0 ? [...donutTop, { label: 'Прочие фразы', value: donutRest }] : donutTop;

    // Funnel
    let carts = 0;
    sheets.forEach((sh) => {
      const cartCol = findAdsCol(sh.columns || [], ['добавленийвкорзину', 'корзина', 'вкорзину', 'addtocart']);
      if (cartCol) carts += (sh.rows || []).reduce((s: number, r: any) => s + toAdsNum(r?.[cartCol]), 0);
    });
    const funnel = { shows: adsKpi.shows, clicks: adsKpi.clicks, carts, orders: adsKpi.orders };

    return { daily, keywords, kwSpendTotal, avgCpc, wasted, wastedSum, expensive, donut, funnel };
  }, [adsAnalyticsSheets, adsKpi]);

  // Searchable + sortable view over all keyword phrases that consume budget.
  const adsKwView = React.useMemo(() => {
    const q = adsKwSearch.trim().toLowerCase();
    let list = adsViz.keywords || [];
    if (q) list = list.filter((k: any) => String(k.phrase).toLowerCase().includes(q));
    const { field, dir } = adsKwSort; const mul = dir === 'asc' ? 1 : -1;
    return [...list].sort((a: any, b: any) => {
      if (field === 'phrase') return String(a.phrase).localeCompare(String(b.phrase), 'ru') * mul;
      return ((a[field] || 0) - (b[field] || 0)) * mul;
    });
  }, [adsViz.keywords, adsKwSearch, adsKwSort]);
  const adsKwSortBtn = (field: string) => () => setAdsKwSort((p) => ({ field, dir: p.field === field && p.dir === 'desc' ? 'asc' : 'desc' }));
  const adsKwArw = (field: string) => adsKwSort.field === field ? (adsKwSort.dir === 'asc' ? ' ▲' : ' ▼') : '';

  const handleAdsExcelUpload = async (file: File) => {
    await ensureExcel();
    try {
      const sizeError = ensureExcelFileSize(file);
      if (sizeError) {
        showToast(sizeError, 'error');
        return;
      }

      const buf = await file.arrayBuffer();
      const wb = new lazyLibs.ExcelJS.Workbook();
      await wb.xlsx.load(buf);

      const sheets = wb.worksheets.slice(0, 4).map((ws: any) => {
        const aoa: string[][] = [];
        ws.eachRow({ includeEmpty: true }, (row: any) => {
          const vals = (row.values as any[]).slice(1).map((x: any) => {
            if (x == null) return '';
            if (typeof x === 'object') {
              if (x.text != null) return String(x.text);
              if (x.result != null) return String(x.result);
            }
            return String(x);
          });
          aoa.push(vals);
        });

        const header = (aoa[0] || []).map((h: any, idx: number) => String(h || '').trim() || `Колонка ${idx + 1}`);
        const rows = (aoa.slice(1) || [])
          .map((line: any[]) => {
            const o: Record<string, any> = {};
            header.forEach((h: string, idx: number) => {
              o[h] = line?.[idx] ?? '';
            });
            return o;
          })
          .filter((r: any) => Object.values(r).some((v: any) => String(v || '').trim() !== ''));

        return { name: ws.name || 'Лист', columns: header, rows };
      });

      setAdsAnalyticsSheets(sheets);
      setAdsAnalyticsFileName(file.name || 'ads.xlsx');
      setAdsSheetFilters({});
      setAdsSheetSorts({});
      setAdsUnifiedFilter('');
      setAdsUnifiedSort({ col: '__sheet', dir: 'asc' });
      showToast(`Загружено листов: ${sheets.length}`, 'success');
    } catch (e: any) {
      console.error('handleAdsExcelUpload error', e);
      showToast('Не удалось загрузить Excel рекламы', 'error');
    }
  };
  const getUploadedRowTax = (row: any) => {
    return Number(row?.sales_net || 0) * getCurrentUploadedTaxRate();
  };
  const getUploadedHeadlineProfit = (summary: any) => {
    const rows = sortedFilteredUploadedAnalytics || [];
    const profitAfterTax = rows.reduce((acc: number, row: any) => acc + getUploadedProfitAfterTax(row), 0);
    const storage = Number(summary?.storage_sum || 0);
    const withhold = Number(summary?.withhold_sum || 0);
    return profitAfterTax - storage - withhold;
  };
  const getUploadedHeadlineProfitNet = (summary: any) => getUploadedHeadlineProfit(summary) - Number(uploadedExtraCosts || 0);
  // База для разнесения «нераспределяемых» трат: реклама и хранение приходят на служебных
  // строках («артикул 0») и не привязаны к товару. Разносим их по доле продаж.
  const uploadedAllocBase = useMemo(() => {
    const rows = uploadedReportAnalytics || [];
    let salesAbs = 0;
    let unalloc = 0;
    rows.forEach((r: any) => {
      salesAbs += Math.abs(Number(r?.sales_net || 0));
      unalloc += Number(r?.withhold_sum || 0) + Number(r?.storage_sum || 0);
    });
    return { salesAbs, unalloc };
  }, [uploadedReportAnalytics]);

  // Прибыль строки по текущему режиму налогообложения:
  //  УСН        — минус налог с выручки (ставка 1/6/15%), как раньше;
  //  ОСНО + НДС — реклама/хранение разносятся по доле продаж, минус НДС к уплате
  //               (выходной − входной, включая НДС разнесённых трат) и налог на прибыль 25%.
  const getUploadedRowProfitAfterTaxes = (
    toPayRaw: number, salesNet: number, costTotal: number,
    commissionVat: number, logistics: number, ownUnalloc: number,
  ) => {
    if (!uploadedVatMode) return (toPayRaw - costTotal) - salesNet * getCurrentUploadedTaxRate();
    const VAT = 0.22;
    const ex = (a: number) => (a * VAT) / (1 + VAT);
    const vSales = (a: number) => uploadedVatSalesIncluded ? ex(a) : a * VAT;
    const vCost = (a: number) => uploadedVatCostIncluded ? ex(a) : a * VAT;
    const share = uploadedAllocBase.salesAbs > 0 ? Math.abs(salesNet) / uploadedAllocBase.salesAbs : 0;
    const unalloc = uploadedAllocBase.unalloc * share;   // доля рекламы/хранения этой строки
    const toPay = toPayRaw + ownUnalloc;                 // убираем собственные удержания строки
    const servicesVat = commissionVat + ex(logistics) + ex(unalloc);
    const vatToPay = vSales(salesNet) - vCost(costTotal) - servicesVat;
    const before = toPay - costTotal - unalloc - vatToPay;
    return before - Math.max(0, before) * 0.25;
  };
  const getUploadedProfitAfterTax = (row: any) => {
    const sold = Number(row?.sold_qty || 0);
    const cost = getUploadedCostValue(row);
    return getUploadedRowProfitAfterTaxes(
      Number(row?.to_pay_total || 0),
      Number(row?.sales_net || 0),
      cost * sold,
      Number(row?.wb_commission_vat || 0),
      Number(row?.logistics_sum || 0),
      Number(row?.withhold_sum || 0) + Number(row?.storage_sum || 0),
    );
  };
  const getUploadedAvgProfitAfterTax = (row: any) => {
    const sold = Number(row?.sold_qty || 0);
    if (sold <= 0) return 0;
    return getUploadedProfitAfterTax(row) / sold;
  };

  const isUploadedColVisible = (key: string) => uploadedVisibleCols[key] !== false;

  const uploadedNameGroups = useMemo(() => {
    const groups = new Map<string, string[]>();
    (uploadedReportAnalytics || []).forEach((row: any) => {
      const name = String(row?.name || 'Без названия').trim();
      const code = String(row?.code || '').trim();
      if (!groups.has(name)) groups.set(name, []);
      const arr = groups.get(name)!;
      if (code && !arr.includes(code)) arr.push(code);
    });
    return Array.from(groups.entries()).sort((a, b) => a[0].localeCompare(b[0], 'ru'));
  }, [uploadedReportAnalytics]);

  const chartUploadedKeys = useMemo(() => Object.keys(uploadedDailySeries || {}), [uploadedDailySeries]);

  useEffect(() => {
    if (chartUploadedKeys.length === 0) return;
    if (!uploadedChartKey || !chartUploadedKeys.includes(uploadedChartKey)) {
      setUploadedChartKey(chartUploadedKeys[0]);
    }
  }, [chartUploadedKeys, uploadedChartKey]);

  const chartUploadedData = useMemo(() => {
    const item = uploadedChartKey ? (uploadedDailySeries || {})[uploadedChartKey] : null;
    const pts = Array.isArray(item?.points) ? item.points : [];
    const maxV = Math.max(1, ...pts.map((p: any) => Number(p?.[uploadedChartMetric] || 0)));
    return pts.map((p: any, i: number) => ({
      idx: i,
      date: String(p?.date || ''),
      value: Number(p?.[uploadedChartMetric] || 0),
      yNorm: Number(p?.[uploadedChartMetric] || 0) / maxV,
    }));
  }, [uploadedDailySeries, uploadedChartKey, uploadedChartMetric]);

  const sortedFilteredUploadedAnalytics = useMemo(() => {
    const q = uploadedSearch.trim().toLowerCase();
    const filtered = (uploadedReportAnalytics || []).filter((row: any) => {
      const rowName = String(row?.name || 'Без названия').trim();
      const rowCode = String(row?.code || '').trim();
      const nameEnabled = uploadedSelectedNames[rowName] !== false;
      const codeEnabled = uploadedSelectedNameCodes[`${rowName}|${rowCode}`] !== false;
      if (!nameEnabled || !codeEnabled) return false;
      if (!q) return true;
      return String(row?.code || '').toLowerCase().includes(q) || String(row?.name || '').toLowerCase().includes(q);
    });

    const rowMetric = (row: any, key: string) => {
      const cost = getUploadedCostValue(row);
      if (key === 'cost') return cost;
      if (key === 'avg_profit') return getUploadedAvgProfitAfterTax(row);
      if (key === 'profit_total') return getUploadedProfitAfterTax(row);
      return row?.[key];
    };

    const sorted = [...filtered].sort((a: any, b: any) => {
      const av = rowMetric(a, uploadedSortKey as string);
      const bv = rowMetric(b, uploadedSortKey as string);
      if (uploadedSortKey === 'name' || uploadedSortKey === 'code') {
        return String(av || '').localeCompare(String(bv || ''), 'ru');
      }
      return Number(av || 0) - Number(bv || 0);
    });

    return uploadedSortDir === 'asc' ? sorted : sorted.reverse();
  }, [uploadedReportAnalytics, uploadedSearch, uploadedSortKey, uploadedSortDir, uploadedSelectedNames, uploadedSelectedNameCodes, uploadedCostByKey, uploadedPersistedCostByCode]);

  const renderedUploadedAnalyticsRows = useMemo(() => (
    (sortedFilteredUploadedAnalytics || []).slice(0, UPLOADED_TABLE_RENDER_LIMIT)
  ), [sortedFilteredUploadedAnalytics]);

  const uploadedTableRowsHidden = Math.max(0, (sortedFilteredUploadedAnalytics || []).length - renderedUploadedAnalyticsRows.length);

  const uploadedSummaryForView = useMemo(() => {
    const rows = sortedFilteredUploadedAnalytics || [];
    const baseSummary = uploadedReportSummary || {};
    const sales_net = rows.reduce((acc: number, x: any) => acc + Number(x?.sales_net || 0), 0);
    const returns_gross = rows.reduce((acc: number, x: any) => acc + Number(x?.returns_gross || 0), 0);
    const logistics_sum = rows.reduce((acc: number, x: any) => acc + Number(x?.logistics_sum || 0), 0);
    const payout_net = rows.reduce((acc: number, x: any) => acc + Number(x?.payout_net || 0), 0);
    const fine_sum = rows.reduce((acc: number, x: any) => acc + Number(x?.fine_sum || 0), 0);
    const storage_sum = rows.reduce((acc: number, x: any) => acc + Number(x?.storage_sum || 0), 0);
    const withhold_sum = rows.reduce((acc: number, x: any) => acc + Number(x?.withhold_sum || 0), 0);
    const to_pay_total = rows.reduce((acc: number, x: any) => acc + Number(x?.to_pay_total || 0), 0);
    const sold_qty = rows.reduce((acc: number, x: any) => acc + Number(x?.sold_qty || 0), 0);
    const return_qty = rows.reduce((acc: number, x: any) => acc + Number(x?.return_qty || 0), 0);
    const acquiring_sum = rows.reduce((acc: number, x: any) => acc + Number(x?.acquiring_sum || 0), 0);
    const tax_sum = rows.reduce((acc: number, x: any) => acc + getUploadedRowTax(x), 0);
    const acquiring_percent = sales_net > 0 ? (acquiring_sum / sales_net) * 100 : 0;
    const profit_total = rows.reduce((acc: number, x: any) => {
      const sold = Number(x?.sold_qty || 0);
      const cost = getUploadedCostValue(x);
      const avg = sold > 0 ? (Number(x?.to_pay_total || 0) / sold) - cost : 0;
      const baseProfit = avg * sold;
      return acc + (baseProfit - getUploadedRowTax(x));
    }, 0);

    return {
      ...baseSummary,
      items: rows.length,
      sales_net,
      returns_gross,
      logistics_sum,
      payout_net,
      fine_sum,
      storage_sum,
      withhold_sum,
      to_pay_total,
      sold_qty,
      return_qty,
      acquiring_sum,
      acquiring_percent,
      tax_sum,
      profit_total,
    };
  }, [sortedFilteredUploadedAnalytics, uploadedReportSummary, uploadedExtraCosts, uploadedCostByKey, uploadedPersistedCostByCode]);

